{
  "name": "AllergyGuard - Planty Scan",
  "description": "A nature-inspired allergy safety app. Scan product labels or search ingredients to instantly check against custom user profiles and allergen groups with a simple red/green safety light.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Profile {
  id: string;
  name: string;
  allergy: string;
  enabled: boolean;
  groupId?: string;
}

export interface Group {
  id: string;
  name: string;
  enabled: boolean;
}

export interface HistoryItem {
  id: string;
  timestamp: number;
  productName: string;
  isSafe: boolean;
  allergensFound: string[];
  imageUrl?: string;
}

export interface User {
  email: string;
}

export interface AnalysisResult {
  productName: string;
  isSafe: boolean;
  allergensFound: string[];
  summary: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "The name of the product being analyzed.",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "True if none of the allergens are present in the product.",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "A list of allergens from the input list that were detected in the product.",
    },
    summary: {
      type: Type.STRING,
      description: "A brief explanation of why the product is safe or unsafe based on ingredients.",
    },
  },
  required: ["productName", "isSafe", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Analyze the following product for these allergens: ${activeAllergens.join(", ")}.
    ${input.text ? `Product Information/Ingredients: ${input.text}` : "Please analyze the provided image of the product label or packaging."}
    If the allergens are found in the ingredients (or likely present due to manufacturing warnings), mark isSafe as false.
    Be extremely cautious. If you aren't sure about an ingredient's relation to an allergy, assume it's unsafe.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
    },
  });

  return JSON.parse(response.text.trim());
}

import React, { useState, useEffect, useCallback } from 'react';
import { User, Profile, Group, HistoryItem } from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import ProfileManager from './components/ProfileManager';
import Scanner from './components/Scanner';
import History from './components/History';
import Navigation from './components/Navigation';

type View = 'dashboard' | 'profiles' | 'scan' | 'history';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<View>('dashboard');
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // Persistence
  useEffect(() => {
    const savedUser = localStorage.getItem('allergy_user');
    const savedProfiles = localStorage.getItem('allergy_profiles');
    const savedGroups = localStorage.getItem('allergy_groups');
    const savedHistory = localStorage.getItem('allergy_history');

    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedProfiles) setProfiles(JSON.parse(savedProfiles));
    if (savedGroups) setGroups(JSON.parse(savedGroups));
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('allergy_user', JSON.stringify(user));
    localStorage.setItem('allergy_profiles', JSON.stringify(profiles));
    localStorage.setItem('allergy_groups', JSON.stringify(groups));
    localStorage.setItem('allergy_history', JSON.stringify(history));
  }, [user, profiles, groups, history]);

  const handleLogin = (email: string) => setUser({ email });
  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('allergy_user');
  };

  const addProfile = (name: string, allergy: string, groupId?: string) => {
    const newProfile: Profile = {
      id: crypto.randomUUID(),
      name,
      allergy,
      enabled: true,
      groupId
    };
    setProfiles(prev => [...prev, newProfile]);
  };

  const toggleProfile = (id: string) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, enabled: !p.enabled } : p));
  };

  const deleteProfile = (id: string) => {
    setProfiles(prev => prev.filter(p => p.id !== id));
  };

  const addGroup = (name: string) => {
    const newGroup: Group = { id: crypto.randomUUID(), name, enabled: true };
    setGroups(prev => [...prev, newGroup]);
  };

  const toggleGroup = (id: string) => {
    setGroups(prev => prev.map(g => g.id === id ? { ...g, enabled: !g.enabled } : g));
  };

  const deleteGroup = (id: string) => {
    setGroups(prev => prev.filter(g => g.id !== id));
    setProfiles(prev => prev.map(p => p.groupId === id ? { ...p, groupId: undefined } : p));
  };

  const addToHistory = (item: Omit<HistoryItem, 'id' | 'timestamp'>) => {
    const newItem: HistoryItem = {
      ...item,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    setHistory(prev => [newItem, ...prev].slice(0, 50));
  };

  const activeAllergens = profiles
    .filter(p => {
      if (!p.enabled) return false;
      if (p.groupId) {
        const group = groups.find(g => g.id === p.groupId);
        return group?.enabled ?? true;
      }
      return true;
    })
    .map(p => p.allergy);

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen planty-gradient leaf-pattern pb-24 relative max-w-md mx-auto shadow-2xl bg-white overflow-x-hidden flex flex-col">
      <header className="p-6 flex justify-between items-center bg-white/80 backdrop-blur-md sticky top-0 z-50 border-b border-green-50">
        <div>
          <h1 className="text-2xl font-bold text-green-800">AllergyGuard</h1>
          <p className="text-xs text-green-600 font-medium">Protecting your wellness</p>
        </div>
        <button 
          onClick={handleLogout}
          className="p-2 text-green-700 hover:bg-green-50 rounded-full transition-colors"
          title="Logout"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
          </svg>
        </button>
      </header>

      <main className="flex-1 overflow-y-auto p-4">
        {view === 'dashboard' && (
          <Dashboard 
            profiles={profiles} 
            groups={groups} 
            onNavigate={() => setView('scan')} 
            activeCount={activeAllergens.length}
          />
        )}
        {view === 'profiles' && (
          <ProfileManager 
            profiles={profiles} 
            groups={groups} 
            onAddProfile={addProfile}
            onToggleProfile={toggleProfile}
            onDeleteProfile={deleteProfile}
            onAddGroup={addGroup}
            onToggleGroup={toggleGroup}
            onDeleteGroup={deleteGroup}
          />
        )}
        {view === 'scan' && (
          <Scanner 
            activeAllergens={activeAllergens} 
            onScanComplete={addToHistory}
          />
        )}
        {view === 'history' && (
          <History history={history} />
        )}
      </main>

      <Navigation currentView={view} setView={setView} />
    </div>
  );
}

import React from 'react';

interface Props {
  currentView: string;
  setView: (view: any) => void;
}

const Navigation: React.FC<Props> = ({ currentView, setView }) => {
  const tabs = [
    { id: 'dashboard', label: 'Home', icon: 'M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6' },
    { id: 'profiles', label: 'Profiles', icon: 'M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z' },
    { id: 'scan', label: 'Scan', icon: 'M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z' },
    { id: 'history', label: 'History', icon: 'M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z' },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/95 backdrop-blur-lg border-t border-green-100 flex justify-around items-center h-20 px-4 z-50">
      {tabs.map(tab => (
        <button
          key={tab.id}
          onClick={() => setView(tab.id)}
          className={`flex flex-col items-center gap-1 transition-all ${
            currentView === tab.id ? 'text-green-600 scale-110' : 'text-gray-400 hover:text-green-400'
          }`}
        >
          <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={currentView === tab.id ? 2.5 : 2} d={tab.icon} />
          </svg>
          <span className="text-[10px] font-bold uppercase tracking-wider">{tab.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default Navigation;

import React, { useState } from 'react';

interface Props {
  onLogin: (email: string) => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [email, setEmail] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) onLogin(email);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-8 planty-gradient leaf-pattern">
      <div className="w-full max-w-sm bg-white p-8 rounded-3xl shadow-xl border border-green-50 space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center space-y-2">
          <div className="bg-green-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 21l-8-9a5 5 0 010-7 5 5 0 017 0l1 1 1-1a5 5 0 017 0 5 5 0 010 7l-8 9z" />
            </svg>
          </div>
          <h1 className="text-3xl font-bold text-gray-800">Welcome</h1>
          <p className="text-gray-500 text-sm">Sign in to start checking your safety</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs font-bold text-green-700 uppercase tracking-widest mb-2 px-1">Email Address</label>
            <input
              type="email"
              required
              className="w-full px-5 py-4 rounded-2xl bg-gray-50 border-0 ring-1 ring-gray-200 focus:ring-2 focus:ring-green-500 transition-all text-gray-800"
              placeholder="nature@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <button
            type="submit"
            className="w-full py-4 rounded-2xl bg-green-600 text-white font-bold text-lg hover:bg-green-700 active:scale-95 transition-all shadow-lg shadow-green-200"
          >
            Get Started
          </button>
        </form>

        <p className="text-center text-xs text-gray-400">
          Your data is stored locally for maximum privacy.
        </p>
      </div>
    </div>
  );
};

export default Login;

import React from 'react';
import { Profile, Group } from '../types';

