export default Dashboard;

import React, { useState } from 'react';
import { Profile, Group } from '../types';

interface Props {
  profiles: Profile[];
  groups: Group[];
  onAddProfile: (name: string, allergy: string, groupId?: string) => void;
  onToggleProfile: (id: string) => void;
  onDeleteProfile: (id: string) => void;
  onAddGroup: (name: string) => void;
  onToggleGroup: (id: string) => void;
  onDeleteGroup: (id: string) => void;
}

const ProfileManager: React.FC<Props> = ({ 
  profiles, groups, onAddProfile, onToggleProfile, onDeleteProfile, 
  onAddGroup, onToggleGroup, onDeleteGroup 
}) => {
  const [showAddProfile, setShowAddProfile] = useState(false);
  const [showAddGroup, setShowAddGroup] = useState(false);
  const [newName, setNewName] = useState('');
  const [newAllergy, setNewAllergy] = useState('');
  const [newGroupName, setNewGroupName] = useState('');
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const handleAddProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName && newAllergy) {
      onAddProfile(newName, newAllergy, selectedGroupId || undefined);
      setNewName('');
      setNewAllergy('');
      setSelectedGroupId('');
      setShowAddProfile(false);
    }
  };

  const handleAddGroup = (e: React.FormEvent) => {
    e.preventDefault();
    if (newGroupName) {
      onAddGroup(newGroupName);
      setNewGroupName('');
      setShowAddGroup(false);
    }
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right duration-500 pb-10">
      {/* Groups Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h2 className="text-xl font-bold text-gray-800">Groups</h2>
          <button 
            onClick={() => setShowAddGroup(true)}
            className="text-green-600 text-sm font-bold bg-green-50 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-green-100 transition-colors"
          >
            <span>+</span> Add Group
          </button>
        </div>

        {groups.length === 0 && !showAddGroup ? (
          <p className="text-center py-6 text-gray-400 text-xs italic">Create groups to organize families or events</p>
        ) : (
          <div className="space-y-3">
            {showAddGroup && (
              <form onSubmit={handleAddGroup} className="bg-white p-5 rounded-3xl border-2 border-green-200 shadow-lg space-y-4 animate-in zoom-in duration-200">
                <input
                  autoFocus
                  className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                  placeholder="Group Name (e.g. Family Trip)"
                  value={newGroupName}
                  onChange={e => setNewGroupName(e.target.value)}
                />
                <div className="flex gap-2">
                  <button type="submit" className="flex-1 bg-green-600 text-white py-2 rounded-xl text-sm font-bold">Save Group</button>
                  <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-2 text-gray-500 text-sm font-bold">Cancel</button>
                </div>
              </form>
            )}
            {groups.map(group => (
              <div key={group.id} className="bg-white p-4 rounded-2xl border border-green-50 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-3 h-3 rounded-full ${group.enabled ? 'bg-green-500 shadow-sm shadow-green-200' : 'bg-gray-300'}`} />
                  <span className={`font-bold text-sm ${group.enabled ? 'text-gray-800' : 'text-gray-400 line-through'}`}>{group.name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tighter transition-colors ${group.enabled ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                    {group.enabled ? 'Enabled' : 'Disabled'}
                  </button>
                  <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-300 hover:text-red-400">
                    <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>

      {/* Profiles Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h2 className="text-xl font-bold text-gray-800">Profiles</h2>
          <button 
            onClick={() => setShowAddProfile(true)}
            className="text-green-600 text-sm font-bold bg-green-50 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-green-100 transition-colors"
          >
            <span>+</span> Add Profile
          </button>
        </div>

        <div className="space-y-4">
          {showAddProfile && (
            <form onSubmit={handleAddProfile} className="bg-white p-6 rounded-3xl border-2 border-green-200 shadow-lg space-y-4 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                placeholder="Name"
                value={newName}
                onChange={e => setNewName(e.target.value)}
              />
              <input
                className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                placeholder="Allergy (e.g. Peanuts, Shellfish)"
                value={newAllergy}
                onChange={e => setNewAllergy(e.target.value)}
              />
              <select 
                className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                value={selectedGroupId}
                onChange={e => setSelectedGroupId(e.target.value)}
              >
                <option value="">No Group</option>
                {groups.map(g => (
                  <option key={g.id} value={g.id}>{g.name}</option>
                ))}
              </select>
              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-green-600 text-white py-2 rounded-xl text-sm font-bold shadow-md">Add Profile</button>
                <button type="button" onClick={() => setShowAddProfile(false)} className="px-4 py-2 text-gray-500 text-sm font-bold">Cancel</button>
              </div>
            </form>
          )}

          {profiles.length === 0 ? (
            <div className="text-center py-10">
              <p className="text-gray-400 text-sm">Add your first profile to begin protection.</p>
            </div>
          ) : (
            <div className="grid gap-4">
              {profiles.map(profile => {
                const group = groups.find(g => g.id === profile.groupId);
                const isGroupDisabled = group && !group.enabled;
                const effectiveEnabled = profile.enabled && !isGroupDisabled;

                return (
                  <div key={profile.id} className={`bg-white p-5 rounded-3xl border transition-all ${effectiveEnabled ? 'border-green-100 shadow-sm' : 'border-gray-100 opacity-60'}`}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="flex items-center gap-3">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-lg ${effectiveEnabled ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-400'}`}>
                          {profile.name[0].toUpperCase()}
                        </div>
                        <div>
                          <p className="font-bold text-gray-800">{profile.name}</p>
                          {group && <p className="text-[10px] text-green-500 font-bold uppercase tracking-wider">Group: {group.name}</p>}
                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tighter ${profile.enabled ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                          {profile.enabled ? 'ON' : 'OFF'}
                        </button>
                        <button onClick={() => onDeleteProfile(profile.id)} className="p-1 text-gray-300 hover:text-red-400">
