      {isScanning && (
        <div className="relative rounded-[3rem] overflow-hidden bg-black aspect-[3/4] shadow-2xl">
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className="w-full h-full object-cover"
          />
