import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "The name of the product being analyzed.",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "True if none of the allergens are present in the product.",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "A list of allergens from the input list that were detected in the product.",
    },
    summary: {
      type: Type.STRING,
      description: "A brief explanation of why the product is safe or unsafe based on ingredients or barcode data.",
    },
  },
  required: ["productName", "isSafe", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Identify the food product and analyze it for these allergens: ${activeAllergens.join(", ")}.
    ${input.text ? `Input Info: ${input.text}` : "Analyze the image. Look for ingredient lists, product names, or barcodes to identify the item."}

    Rules:
    1. If the product contains any of the specified allergens (including traces or 'may contain' warnings), set isSafe to false.
    2. If the information is insufficient to guarantee safety, assume it is NOT safe.
    3. Return the detected product name and a concise summary.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
    },
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Analysis failed to produce valid result.");
  }
}

