    e.preventDefault();
    if (newName && selectedAllergies.length > 0) {
      onAddProfile(newName, selectedAllergies, selectedGroupId || undefined);
      setNewName('');
      setSelectedAllergies([]);
      setSelectedGroupId('');
      setShowAddProfile(false);
    }
  };

  const handleAddGroup = (e: React.FormEvent) => {
    e.preventDefault();
    if (newGroupName) {
      onAddGroup(newGroupName);
      setNewGroupName('');
      setShowAddGroup(false);
    }
  };

  return (
    <div className="space-y-8 animate-in slide-in-from-right duration-500 pb-10">
      {/* Groups Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h2 className="text-xl font-bold text-gray-800">קבוצות</h2>
          <button 
            onClick={() => setShowAddGroup(true)}
            className="text-green-600 text-sm font-bold bg-green-50 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-green-100 transition-colors"
          >
            <span>+</span> הוסף קבוצה
          </button>
        </div>

        {groups.length === 0 && !showAddGroup ? (
          <p className="text-center py-6 text-gray-400 text-xs italic">צור קבוצות לניהול משפחה או אירועים</p>
        ) : (
          <div className="space-y-3">
            {showAddGroup && (
              <form onSubmit={handleAddGroup} className="bg-white p-5 rounded-3xl border-2 border-green-200 shadow-lg space-y-4 animate-in zoom-in duration-200">
                <input
                  autoFocus
                  className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                  placeholder="שם הקבוצה (למשל: משפחה)"
                  value={newGroupName}
                  onChange={e => setNewGroupName(e.target.value)}
                />
                <div className="flex gap-2">
                  <button type="submit" className="flex-1 bg-green-600 text-white py-2 rounded-xl text-sm font-bold">שמור קבוצה</button>
                  <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-2 text-gray-500 text-sm font-bold">ביטול</button>
                </div>
              </form>
            )}
            {groups.map(group => (
              <div key={group.id} className="bg-white p-4 rounded-2xl border border-green-50 shadow-sm flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-3 h-3 rounded-full ${group.enabled ? 'bg-green-500' : 'bg-gray-300'}`} />
                  <span className={`font-bold text-sm ${group.enabled ? 'text-gray-800' : 'text-gray-400 line-through'}`}>{group.name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tighter transition-colors ${group.enabled ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                    {group.enabled ? 'פעיל' : 'כבוי'}
                  </button>
                  <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-300 hover:text-red-400">
                    <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
