      {/* Profiles Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h2 className="text-xl font-bold text-gray-800">פרופילים</h2>
          <button 
            onClick={() => setShowAddProfile(true)}
            className="text-green-600 text-sm font-bold bg-green-50 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-green-100 transition-colors"
          >
            <span>+</span> הוסף פרופיל
          </button>
        </div>

        <div className="space-y-4">
          {showAddProfile && (
            <form onSubmit={handleAddProfile} className="bg-white p-6 rounded-3xl border-2 border-green-200 shadow-lg space-y-4 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                placeholder="שם הפרופיל"
                value={newName}
                onChange={e => setNewName(e.target.value)}
              />

              <div className="space-y-2">
                <label className="text-xs font-bold text-gray-500 uppercase tracking-widest px-1">בחר אלרגיות:</label>
                <div className="grid grid-cols-2 gap-2">
                  {COMMON_ALLERGENS.map(allergy => (
                    <label key={allergy} className={`flex items-center gap-2 p-2 rounded-xl border text-sm transition-all cursor-pointer ${selectedAllergies.includes(allergy) ? 'bg-green-50 border-green-500 text-green-700 font-bold' : 'bg-gray-50 border-transparent text-gray-600'}`}>
                      <input 
                        type="checkbox" 
                        className="hidden" 
                        checked={selectedAllergies.includes(allergy)}
                        onChange={() => handleToggleAllergy(allergy)}
                      />
                      <div className={`w-4 h-4 rounded-sm border flex items-center justify-center ${selectedAllergies.includes(allergy) ? 'bg-green-600 border-green-600' : 'bg-white border-gray-300'}`}>
                        {selectedAllergies.includes(allergy) && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                      </div>
                      {allergy}
                    </label>
                  ))}
                </div>
              </div>

              <select 
                className="w-full px-4 py-3 rounded-xl bg-gray-50 border-0 focus:ring-2 focus:ring-green-500 text-sm"
                value={selectedGroupId}
                onChange={e => setSelectedGroupId(e.target.value)}
              >
                <option value="">ללא קבוצה</option>
                {groups.map(g => (
                  <option key={g.id} value={g.id}>{g.name}</option>
                ))}
              </select>
              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-green-600 text-white py-2 rounded-xl text-sm font-bold shadow-md">הוסף פרופיל</button>
                <button type="button" onClick={() => setShowAddProfile(false)} className="px-4 py-2 text-gray-500 text-sm font-bold">ביטול</button>
              </div>
            </form>
          )}

          {profiles.length === 0 ? (
            <div className="text-center py-10">
              <p className="text-gray-400 text-sm">הוסף את הפרופיל הראשון שלך כדי להתחיל.</p>
            </div>
          ) : (
            <div className="grid gap-4">
              {profiles.map(profile => {
                const group = groups.find(g => g.id === profile.groupId);
                const isGroupDisabled = group && !group.enabled;
                const effectiveEnabled = profile.enabled && !isGroupDisabled;

                return (
                  <div key={profile.id} className={`bg-white p-5 rounded-3xl border transition-all ${effectiveEnabled ? 'border-green-100 shadow-sm' : 'border-gray-100 opacity-60'}`}>
