                        </div>
                      </div>
                      <div className="flex items-center gap-2">
                        <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-tighter ${profile.enabled ? 'bg-green-50 text-green-600' : 'bg-gray-100 text-gray-400'}`}>
                          {profile.enabled ? 'פעיל' : 'כבוי'}
