                        <button onClick={() => onDeleteProfile(profile.id)} className="p-1 text-gray-300 hover:text-red-400">
                          <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                        </button>
                      </div>
                    </div>
                    <div className={`p-3 rounded-xl border ${effectiveEnabled ? 'bg-red-50 border-red-100' : 'bg-gray-50 border-gray-100'}`}>
                      <p className={`text-xs font-bold uppercase tracking-widest ${effectiveEnabled ? 'text-red-600' : 'text-gray-400'}`}>אלרגיות</p>
                      <div className="flex flex-wrap gap-1 mt-1">
                        {profile.allergies.map(a => (
                          <span key={a} className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${effectiveEnabled ? 'bg-red-600 text-white' : 'bg-gray-300 text-white'}`}>{a}</span>
                        ))}
                      </div>
                    </div>
                    {isGroupDisabled && (
                      <p className="mt-2 text-[10px] text-orange-500 font-bold italic">* הפרופיל כבוי בגלל הגדרות הקבוצה</p>
