  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setIsScanning(true);
      setError(null);
      setResult(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("לא ניתן לגשת למצלמה. בדוק הרשאות.");
      setIsScanning(false);
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsScanning(false);
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    const context = canvasRef.current.getContext('2d');
    if (!context) return;

    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);

    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.8).split(',')[1];

    stopCamera();
    await performAnalysis({ imageBase64: base64Image });
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;
    await performAnalysis({ text: searchQuery });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError("נדרשת הגנה פעילה. הפעל פרופיל קודם.");
      return;
    }

    setIsAnalyzing(true);
    setResult(null);
    setError(null);

    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
        imageUrl: input.imageBase64 ? `data:image/jpeg;base64,${input.imageBase64}` : undefined
      });
    } catch (err) {
      setError("שגיאת רשת או ניתוח. נסה שוב.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="space-y-4">
        <h2 className="text-xl font-bold text-gray-800 px-1">בדוק מוצר</h2>
        <form onSubmit={handleSearch} className="relative group">
          <input
            type="text"
            className="w-full pr-12 pl-4 py-4 rounded-3xl bg-white border border-green-100 shadow-sm focus:ring-2 focus:ring-green-500 focus:border-transparent transition-all"
            placeholder="חפש מוצר או מותג..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <svg className="absolute right-4 top-4 h-6 w-6 text-gray-400 group-focus-within:text-green-500 transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          {searchQuery && (
            <button type="submit" disabled={isAnalyzing} className="absolute left-3 top-3 bg-green-600 text-white px-4 py-1.5 rounded-2xl text-xs font-bold shadow-md active:scale-95 transition-all disabled:opacity-50">
              {isAnalyzing ? '...' : 'בדוק'}
            </button>
          )}
        </form>
      </div>

      {!isScanning && !result && !isAnalyzing && (
        <button 
          onClick={startCamera}
          className="w-full aspect-square bg-green-50 rounded-[3rem] border-2 border-dashed border-green-200 flex flex-col items-center justify-center gap-4 group hover:bg-green-100/50 transition-all active:scale-[0.98]"
        >
          <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center text-green-600 shadow-md group-hover:scale-110 transition-transform">
            <svg className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            </svg>
          </div>
          <div className="text-center">
            <p className="font-bold text-green-800">סרוק תווית או ברקוד</p>
            <p className="text-xs text-green-600 px-10">הבינה המלאכותית תזהה אלרגיות מרכיבים או קודים</p>
          </div>
        </button>
      )}

      {isScanning && (
        <div className="relative rounded-[3rem] overflow-hidden bg-black aspect-[3/4] shadow-2xl animate-in zoom-in duration-300">
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
          <div className="absolute inset-0 border-[24px] border-black/40 flex items-center justify-center">
            <div className="w-72 h-48 border-2 border-green-400 rounded-2xl relative">
              <div className="absolute top-0 right-0 w-4 h-4 border-t-4 border-r-4 border-white -mr-1 -mt-1 rounded-tr-md"></div>
              <div className="absolute top-0 left-0 w-4 h-4 border-t-4 border-l-4 border-white -ml-1 -mt-1 rounded-tl-md"></div>
              <div className="absolute bottom-0 right-0 w-4 h-4 border-b-4 border-r-4 border-white -mr-1 -mb-1 rounded-br-md"></div>
              <div className="absolute bottom-0 left-0 w-4 h-4 border-b-4 border-l-4 border-white -ml-1 -mb-1 rounded-bl-md"></div>
            </div>
          </div>
          <div className="absolute bottom-10 inset-x-0 flex justify-center gap-6">
            <button onClick={stopCamera} className="w-14 h-14 bg-black/50 backdrop-blur-md rounded-full flex items-center justify-center text-white border border-white/20">
              <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
            <button onClick={captureAndAnalyze} className="w-20 h-20 bg-white rounded-full shadow-2xl flex items-center justify-center active:scale-90 transition-transform p-1">
              <div className="w-full h-full rounded-full border-[6px] border-green-600 flex items-center justify-center">
                 <div className="w-4 h-4 bg-green-600 rounded-full animate-pulse"></div>
              </div>
            </button>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}

      {isAnalyzing && (
        <div className="text-center py-20 space-y-6 animate-pulse bg-white rounded-[3rem] border border-green-50 shadow-sm">
          <div className="relative w-24 h-24 mx-auto">
             <div className="absolute inset-0 border-4 border-green-100 rounded-full"></div>
             <div className="absolute inset-0 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <div>
            <p className="text-xl font-bold text-green-800">מעבד נתונים...</p>
            <p className="text-sm text-green-600">בודק מול {activeAllergens.length} אלרגיות פעילות</p>
          </div>
        </div>
      )}

      {result && (
        <div className={`rounded-[3rem] p-8 border-[6px] text-center space-y-6 animate-in zoom-in duration-300 shadow-xl ${result.isSafe ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'}`}>
          <div className="flex justify-center">
