          <div className="space-y-2">
            <h3 className="text-2xl font-bold text-gray-800 capitalize leading-tight">{result.productName}</h3>
            <p className={`text-3xl font-black uppercase tracking-widest ${result.isSafe ? 'text-green-600' : 'text-red-600'}`}>
              {result.isSafe ? 'בטוח למאכל' : 'מסוכן למאכל'}
