import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "האם המוצר בטוח לצריכה",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "רשימת אלרגנים שנמצאו בעברית",
    },
    summary: {
      type: Type.STRING,
      description: "הסבר קצר ותמציתי בעברית",
    },
  },
  required: ["productName", "isSafe", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Analyze this food product for these allergens: ${activeAllergens.join(", ")}.
    ${input.text ? `מידע: ${input.text}` : "IDENTIFY the product from the image (look for ingredients, name, or barcode)."}

    CRITICAL RULES:
    1. PRIORITIZE accuracy. If barcode/ingredients are visible, use them.
    2. RESPOND IN HEBREW.
    3. isSafe: FALSE if ANY allergen or "may contain" traces found.
    4. BE CONCISE. FAST RESPONSE REQUIRED.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0.1, // Lower temperature for more deterministic/faster results
    },
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("שגיאה בניתוח הנתונים");
  }
}

