                 <div className="w-6 h-6 bg-green-600 rounded-full"></div>
              </div>
            </button>
          ) : (
            <button 
              onClick={() => { setResult(null); setError(null); setShowDetails(false); }}
              className="px-6 py-2 bg-white/30 backdrop-blur-lg text-white font-bold rounded-full border border-white/50"
            >
              סריקה חדשה
            </button>
          )}
