          <div className="bg-white rounded-t-[2.5rem] shadow-[0_-10px_30px_rgba(0,0,0,0.3)] min-h-[120px] pb-8">
            {/* Arrow Toggle Handle */}
            <button 
              onClick={() => setShowDetails(!showDetails)}
              className="w-full h-10 flex flex-col items-center justify-center group"
            >
              <div className="w-12 h-1 bg-gray-200 rounded-full mb-1 group-hover:bg-green-400 transition-colors" />
              <svg 
                className={`h-5 w-5 text-gray-400 transition-transform duration-300 ${showDetails ? 'rotate-180' : 'rotate-0'}`} 
                fill="none" viewBox="0 0 24 24" stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 15l7-7 7 7" />
              </svg>
            </button>

            {/* Quick Summary Row */}
            <div className="px-8 flex justify-between items-center h-10">
              <div className="flex items-center gap-3">
                <div className={`w-3 h-3 rounded-full ${isAnalyzing ? 'bg-white animate-pulse' : (result?.isSafe ? 'bg-green-500' : 'bg-red-500')}`} />
                <h3 className="font-bold text-gray-800 text-lg">
