import React, { useState, useEffect } from 'react';
import { User, Profile, Group, HistoryItem } from './types';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import ProfileManager from './components/ProfileManager';
import Scanner from './components/Scanner';
import History from './components/History';
import Account from './components/Account';
import Navigation from './components/Navigation';

type View = 'dashboard' | 'profiles' | 'scan' | 'history' | 'account';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<View>('dashboard');
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  useEffect(() => {
    const savedUser = localStorage.getItem('allergy_user');
    const savedProfiles = localStorage.getItem('allergy_profiles');
    const savedGroups = localStorage.getItem('allergy_groups');
    const savedHistory = localStorage.getItem('allergy_history');

    if (savedUser) setUser(JSON.parse(savedUser));
    if (savedProfiles) setProfiles(JSON.parse(savedProfiles));
    if (savedGroups) setGroups(JSON.parse(savedGroups));
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  useEffect(() => {
    if (user) localStorage.setItem('allergy_user', JSON.stringify(user));
    localStorage.setItem('allergy_profiles', JSON.stringify(profiles));
    localStorage.setItem('allergy_groups', JSON.stringify(groups));
    localStorage.setItem('allergy_history', JSON.stringify(history));
  }, [user, profiles, groups, history]);

  const handleLogin = (email: string) => setUser({ email });
  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('allergy_user');
  };

  const addProfile = (name: string, allergies: string[], groupId?: string) => {
    const newProfile: Profile = {
      id: crypto.randomUUID(),
      name,
      allergies,
      enabled: true,
      groupId
    };
    setProfiles(prev => [...prev, newProfile]);
  };

  const toggleProfile = (id: string) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, enabled: !p.enabled } : p));
  };

  const deleteProfile = (id: string) => {
    setProfiles(prev => prev.filter(p => p.id !== id));
  };

  const addGroup = (name: string) => {
    const newGroup: Group = { id: crypto.randomUUID(), name, enabled: true };
    setGroups(prev => [...prev, newGroup]);
  };

  const toggleGroup = (id: string) => {
    setGroups(prev => prev.map(g => g.id === id ? { ...g, enabled: !g.enabled } : g));
  };

  const deleteGroup = (id: string) => {
    setGroups(prev => prev.filter(g => g.id !== id));
    setProfiles(prev => prev.map(p => p.groupId === id ? { ...p, groupId: undefined } : p));
  };

  const addToHistory = (item: Omit<HistoryItem, 'id' | 'timestamp'>) => {
    const newItem: HistoryItem = {
      ...item,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    setHistory(prev => [newItem, ...prev].slice(0, 50));
  };

  const activeAllergens = profiles
    .filter(p => {
      if (!p.enabled) return false;
      if (p.groupId) {
        const group = groups.find(g => g.id === p.groupId);
        return group?.enabled ?? true;
      }
      return true;
    })
    .flatMap(p => p.allergies);

  const uniqueActiveAllergens = Array.from(new Set(activeAllergens));

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen planty-gradient leaf-pattern pb-24 relative max-w-md mx-auto shadow-2xl bg-white overflow-x-hidden flex flex-col" dir="rtl">
      <header className="p-6 flex justify-between items-center bg-white/80 backdrop-blur-md sticky top-0 z-50 border-b border-green-50">
        <div>
          <h1 className="text-2xl font-bold text-green-800">AllergyGuard</h1>
          <p className="text-xs text-green-600 font-medium">שומרים על הבריאות שלך</p>
        </div>
        <div className="w-10 h-10 bg-green-100 rounded-full flex items-center justify-center text-green-600 font-bold border border-green-200">
          {user.email[0].toUpperCase()}
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4">
        {view === 'dashboard' && (
          <Dashboard 
            profiles={profiles} 
            groups={groups} 
            onNavigate={() => setView('scan')} 
            activeCount={uniqueActiveAllergens.length}
          />
        )}
        {view === 'profiles' && (
          <ProfileManager 
            profiles={profiles} 
            groups={groups} 
            onAddProfile={addProfile}
            onToggleProfile={toggleProfile}
            onDeleteProfile={deleteProfile}
            onAddGroup={addGroup}
            onToggleGroup={toggleGroup}
            onDeleteGroup={deleteGroup}
          />
        )}
        {view === 'scan' && (
          <Scanner 
            activeAllergens={uniqueActiveAllergens} 
            onScanComplete={addToHistory}
            onClose={() => setView('dashboard')}
          />
        )}
        {view === 'history' && (
          <History history={history} />
        )}
        {view === 'account' && (
          <Account user={user} onLogout={handleLogout} profilesCount={profiles.length} historyCount={history.length} />
        )}
      </main>

      <Navigation currentView={view} setView={setView} />
    </div>
  );
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setIsScanning(true);
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("גישה למצלמה נכשלה. אנא וודא מתן הרשאות.");
      setIsScanning(false);
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsScanning(false);
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;

    const context = canvasRef.current.getContext('2d');
    if (!context) return;

    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);

    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.7).split(',')[1];

    // We stay in scanning mode but show analyzing state
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError("נדרשת לפחות הגנה פעילה אחת. אנא הפעל פרופיל.");
      return;
    }

    setIsAnalyzing(true);
    setError(null);

    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(false); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
        imageUrl: input.imageBase64 ? `data:image/jpeg;base64,${input.imageBase64}` : undefined
      });
    } catch (err) {
      setError("שגיאה בניתוח המידע. נסה שוב.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  // Rim logic based on state
  const getRimClasses = () => {
    if (isAnalyzing) return 'border-white animate-pulse opacity-80';
    if (!result) return 'border-transparent';
    return result.isSafe 
      ? 'border-green-500 shadow-[inset_0_0_40px_rgba(34,197,94,0.4)]' 
      : 'border-red-500 shadow-[inset_0_0_40px_rgba(239,68,68,0.4)]';
  };

  return (
    <div className="fixed inset-0 z-[60] bg-black overflow-hidden flex flex-col max-w-md mx-auto shadow-2xl" dir="rtl">
      {/* Side Back Arrow */}
      <button 
        onClick={onClose}
        className="absolute top-6 right-6 z-[70] w-12 h-12 bg-black/40 backdrop-blur-md rounded-full flex items-center justify-center text-white border border-white/20 active:scale-90 transition-transform shadow-lg"
      >
        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
        </svg>
      </button>

      {/* Main Camera Viewport */}
      <div className="flex-1 relative bg-black">
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover"
        />

        {/* Dynamic Edge Rim Overlay */}
        <div className={`absolute inset-0 border-[12px] transition-all duration-500 pointer-events-none z-10 ${getRimClasses()}`} />

        {/* Capture Button (always available for quick re-scan) */}
        <div className="absolute bottom-24 inset-x-0 flex justify-center z-20 pointer-events-none">
          <button 
            onClick={captureAndAnalyze}
            disabled={isAnalyzing}
            className={`w-20 h-20 bg-white rounded-full shadow-2xl flex items-center justify-center active:scale-90 transition-all pointer-events-auto p-1 border-4 ${isAnalyzing ? 'border-gray-200 opacity-50' : 'border-green-600'}`}
          >
            <div className={`w-full h-full rounded-full flex items-center justify-center transition-colors ${isAnalyzing ? 'bg-gray-100' : 'bg-green-600'}`}>
              {isAnalyzing ? (
                <div className="w-8 h-8 border-4 border-green-200 border-t-green-600 rounded-full animate-spin" />
              ) : (
                <div className="w-6 h-6 bg-white rounded-full"></div>
              )}
            </div>
          </button>
        </div>
      </div>

      {/* Bottom Result Sheet */}
      {(result || isAnalyzing) && (
        <div 
          className={`absolute bottom-0 inset-x-0 transition-all duration-500 ease-in-out transform z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-100px)]'}`}
        >
          <div className="bg-white rounded-t-[3rem] shadow-[0_-15px_40px_rgba(0,0,0,0.5)] min-h-[160px] pb-12 overflow-hidden border-t-4 border-green-50">
            {/* Toggle Handle / Arrow */}
            <button 
              onClick={() => setShowDetails(!showDetails)}
              className="w-full h-12 flex flex-col items-center justify-center group bg-white"
            >
              <div className="w-16 h-1.5 bg-gray-100 rounded-full mb-1 group-hover:bg-green-200 transition-colors" />
              <svg 
                className={`h-6 w-6 text-green-600 transition-transform duration-500 ${showDetails ? 'rotate-180' : 'rotate-0'}`} 
                fill="none" viewBox="0 0 24 24" stroke="currentColor"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 15l7-7 7 7" />
              </svg>
            </button>

            {/* Header Content (Always Visible when sheet is "closed") */}
            <div className="px-10 flex justify-between items-center h-14">
              <div className="flex items-center gap-4 flex-1 overflow-hidden">
                <div className={`w-4 h-4 rounded-full flex-shrink-0 ${isAnalyzing ? 'bg-gray-300 animate-pulse' : (result?.isSafe ? 'bg-green-500' : 'bg-red-500')}`} />
                <h3 className="font-bold text-gray-800 text-xl truncate leading-tight">
                  {isAnalyzing ? 'מנתח מוצר...' : result?.productName}
                </h3>
              </div>
              <div className="flex flex-col items-end">
                <span className={`text-base font-black uppercase tracking-tighter ${result?.isSafe ? 'text-green-600' : 'text-red-600'}`}>
                  {isAnalyzing ? 'ממתין' : (result?.isSafe ? 'בטוח' : 'מסוכן')}
                </span>
              </div>
            </div>

            {/* Expanded Content */}
            <div className={`px-10 mt-6 space-y-6 transition-opacity duration-300 ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {!result?.isSafe && result?.allergensFound && result.allergensFound.length > 0 && (
                <div className="space-y-3">
                  <p className="text-[10px] font-black text-red-700 uppercase tracking-widest">אלרגנים שזוהו:</p>
                  <div className="flex flex-wrap gap-2">
                    {result.allergensFound.map(a => (
                      <span key={a} className="px-4 py-2 bg-red-600 text-white text-xs font-bold rounded-2xl shadow-md">
                        {a}
                      </span>
                    ))}
                  </div>
                </div>
              )}

              <div className="bg-green-50/50 p-6 rounded-3xl border border-green-100">
                <p className="text-gray-700 text-sm leading-relaxed font-medium">
                  {result?.summary}
                </p>
              </div>

              <button 
                onClick={() => { setResult(null); setShowDetails(false); }}
                className="w-full py-4 bg-gray-900 text-white rounded-[2rem] font-bold text-lg shadow-xl active:scale-95 transition-all"
              >
                נקה תוצאות
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Error Popup */}
      {error && (
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 bg-white p-8 rounded-[3rem] text-center shadow-2xl border-4 border-red-50 z-[90] w-4/5 animate-in zoom-in">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4 text-red-600">
            <svg className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
          </div>
          <p className="text-gray-800 font-bold text-lg mb-6 leading-tight">{error}</p>
          <button onClick={() => setError(null)} className="w-full py-4 bg-gray-800 text-white rounded-2xl font-bold">סגור</button>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

