import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "האם המוצר בטוח לצריכה",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "רשימת אלרגנים שנמצאו בעברית",
    },
    summary: {
      type: Type.STRING,
      description: "הסבר קצר ותמציתי בעברית",
    },
    productType: {
      type: Type.STRING,
      description: "סוג המוצר באנגלית למטרת חיפוש תמונה (למשל: Chocolate bar, Milk carton)",
    }
  },
  required: ["productName", "isSafe", "allergensFound", "summary", "productType"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Analyze this food product for these allergens: ${activeAllergens.join(", ")}.
    ${input.text ? `מידע: ${input.text}` : "IDENTIFY the product from the image accurately."}

    RULES:
    1. Respond in HEBREW.
    2. isSafe: FALSE if ANY allergen or trace warnings found.
    3. BE CONCISE.
    4. MUST provide 'productType' in English for image fetching.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0.1,
    },
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (e) {
    throw new Error("שגיאה בניתוח הנתונים");
  }
}

