import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setIsScanning(true);
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("גישה למצלמה נכשלה");
      setIsScanning(false);
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsScanning(false);
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;
    const context = canvasRef.current.getContext('2d');
    if (!context) return;
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);
    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.7).split(',')[1];
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError("אין אלרגיות פעילות");
      return;
    }
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(false); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
      });
    } catch (err) {
      setError("שגיאה בניתוח הנתונים");
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const rimColor = isAnalyzing 
    ? 'border-white animate-pulse' 
    : result 
      ? result.isSafe ? 'border-neon neon-glow shadow-[inset_0_0_50px_rgba(0,221,145,0.3)]' : 'border-red-500 shadow-[inset_0_0_50px_rgba(239,68,68,0.4)]'
      : 'border-transparent';

  return (
    <div className="fixed inset-0 z-[60] bg-dark overflow-hidden flex flex-col max-w-md mx-auto" dir="rtl">
      <button 
        onClick={onClose}
        className="absolute top-6 right-6 z-[70] w-12 h-12 bg-white/10 backdrop-blur-md rounded flex items-center justify-center text-white border border-white/10"
      >
        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-80" />
        <div className={`absolute inset-0 border-[20px] transition-all duration-700 pointer-events-none z-10 ${rimColor}`} />

        <div className="absolute bottom-24 inset-x-0 flex justify-center z-20">
          <button 
            onClick={captureAndAnalyze}
            disabled={isAnalyzing}
            className={`w-20 h-20 rounded-full flex items-center justify-center transition-all p-1 border-4 ${isAnalyzing ? 'border-white/20' : 'border-neon'}`}
          >
            <div className={`w-full h-full rounded-full flex items-center justify-center ${isAnalyzing ? 'bg-white/10' : 'bg-neon shadow-lg shadow-neon/40'}`}>
               {isAnalyzing ? (
                 <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin" />
               ) : (
                 <div className="w-4 h-4 bg-dark rounded-full"></div>
               )}
            </div>
          </button>
        </div>
      </div>

      {(result || isAnalyzing) && (
        <div className={`absolute bottom-0 inset-x-0 transition-transform duration-500 ease-out z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-110px)]'}`}>
          <div className="bg-white rounded-t-[2rem] min-h-[160px] pb-12 border-t-8 border-neon">
            <button onClick={() => setShowDetails(!showDetails)} className="w-full h-10 flex flex-col items-center justify-center">
              <div className="w-12 h-1 bg-gray-100 rounded-full mb-1" />
              <svg className={`h-5 w-5 text-neon transition-transform ${showDetails ? 'rotate-180' : 'rotate-0'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 15l7-7 7 7" /></svg>
            </button>

            <div className="px-10 flex justify-between items-center h-12">
               <h3 className="font-black text-dark text-xl uppercase tracking-tighter truncate">
                 {isAnalyzing ? 'מנתח...' : result?.productName}
               </h3>
               <span className={`text-xs font-black uppercase px-3 py-1 rounded ${result?.isSafe ? 'bg-neon text-dark' : 'bg-red-500 text-white'}`}>
                 {result?.isSafe ? 'SAFE' : 'UNSAFE'}
               </span>
            </div>

            <div className={`px-10 mt-6 space-y-4 transition-opacity ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {!result?.isSafe && (
                <div className="flex flex-wrap gap-2">
                  {result?.allergensFound.map(a => (
                    <span key={a} className="px-3 py-1 bg-dark text-neon text-[10px] font-black uppercase rounded">{a}</span>
                  ))}
                </div>
              )}
              <div className="bg-gray-50 p-6 rounded-xl border border-gray-100">
                <p className="text-dark text-sm leading-relaxed font-bold italic">{result?.summary}</p>
              </div>
            </div>
          </div>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

