import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setIsScanning(true);
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("גישה למצלמה נכשלה");
      setIsScanning(false);
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsScanning(false);
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;
    const context = canvasRef.current.getContext('2d');
    if (!context) return;
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);
    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.7).split(',')[1];
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(false); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
      });
    } catch (err) {
      setError("שגיאה בניתוח הנתונים");
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const rimColor = isAnalyzing 
    ? 'border-white animate-pulse' 
    : result 
      ? result.isSafe ? 'border-neon shadow-[inset_0_0_80px_rgba(0,221,145,0.2)]' : 'border-red-500 shadow-[inset_0_0_80px_rgba(239,68,68,0.3)]'
      : 'border-transparent';

  return (
    <div className="fixed inset-0 z-[60] bg-dark overflow-hidden flex flex-col max-w-md mx-auto" dir="rtl">
      {/* Side Arrow Back */}
      <button 
        onClick={onClose}
        className="absolute top-6 right-6 z-[70] w-10 h-10 bg-white/20 backdrop-blur-lg rounded-full flex items-center justify-center text-white border border-white/20 active:scale-90 transition-transform"
      >
        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
        <div className={`absolute inset-0 border-[15px] transition-all duration-700 pointer-events-none z-10 ${rimColor}`} />

        <div className="absolute bottom-24 inset-x-0 flex justify-center z-20">
          <button 
            onClick={captureAndAnalyze}
            disabled={isAnalyzing}
            className={`w-16 h-16 rounded-full flex items-center justify-center transition-all p-1 border-4 ${isAnalyzing ? 'border-white/20 opacity-50' : 'border-neon shadow-lg shadow-neon/40'}`}
          >
            <div className={`w-full h-full rounded-full flex items-center justify-center ${isAnalyzing ? 'bg-white/10' : 'bg-white'}`}>
               {isAnalyzing ? (
                 <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin" />
               ) : (
                 <div className="w-4 h-4 bg-dark rounded-full"></div>
               )}
            </div>
          </button>
        </div>
      </div>

      {(result || isAnalyzing) && (
        <div className={`absolute bottom-0 inset-x-0 transition-transform duration-500 ease-out z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-120px)]'}`}>
          <div className="bg-white rounded-t-[2.5rem] min-h-[160px] pb-12 border-t-8 border-neon premium-shadow">
            {/* Arrow Toggle */}
            <button onClick={() => setShowDetails(!showDetails)} className="w-full h-12 flex flex-col items-center justify-center">
              <div className="w-12 h-1 bg-gray-100 rounded-full mb-1" />
              <svg className={`h-6 w-6 text-neon transition-transform ${showDetails ? 'rotate-180' : 'rotate-0'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 15l7-7 7 7" /></svg>
            </button>

            <div className="px-10 flex justify-between items-center h-12">
               <h3 className="font-black text-dark text-xl uppercase tracking-tighter truncate max-w-[70%]">
                 {isAnalyzing ? 'Processing...' : result?.productName}
               </h3>
               <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full ${result?.isSafe ? 'bg-neon text-dark' : 'bg-red-500 text-white'}`}>
                 {result?.isSafe ? 'SAFE' : 'UNSAFE'}
               </span>
            </div>

            <div className={`px-10 mt-8 space-y-6 transition-opacity ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {!result?.isSafe && (
                <div className="space-y-2">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">DANGER DETECTED</p>
                  <div className="flex flex-wrap gap-2">
                    {result?.allergensFound.map(a => (
                      <span key={a} className="px-3 py-1 bg-dark text-neon text-[10px] font-black uppercase rounded">{a}</span>
                    ))}
                  </div>
                </div>
              )}
              <div className="bg-limeLight/50 p-6 rounded-2xl border border-black/5">
                <p className="text-dark text-sm leading-relaxed font-bold italic">{result?.summary}</p>
              </div>
              <button 
                onClick={() => { setResult(null); setShowDetails(false); }}
                className="w-full py-4 bg-dark text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-xl active:scale-95 transition-all"
              >
                Clear Result
              </button>
            </div>
          </div>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

