      {/* Groups Section */}
      <section className="space-y-4 px-2">
        <div className="flex justify-between items-center">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">קבוצות</h3>
          <button onClick={() => setShowAddGroup(true)} className="text-[10px] font-bold text-neon bg-dark px-3 py-1.5 rounded uppercase">Add Group</button>
        </div>

        <div className="space-y-2">
          {showAddGroup && (
            <form onSubmit={handleAddGroup} className="bg-white p-6 rounded-[2rem] border border-black/5 shadow-xl space-y-4 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-neon outline-none text-dark font-bold text-sm"
