import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("גישה למצלמה נכשלה");
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;
    const context = canvasRef.current.getContext('2d');
    if (!context) return;
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);
    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.7).split(',')[1];
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError("אין אלרגיות פעילות");
      return;
    }
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(false); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
      });
    } catch (err) {
      setError("שגיאה בניתוח");
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const rimColor = isAnalyzing 
    ? 'border-white animate-pulse' 
    : result 
      ? result.isSafe ? 'border-warriorGreen shadow-[inset_0_0_80px_rgba(34,197,94,0.3)]' : 'border-red-500 shadow-[inset_0_0_80px_rgba(239,68,68,0.3)]'
      : 'border-transparent';

  return (
    <div className="fixed inset-0 z-[60] bg-dark overflow-hidden flex flex-col max-w-md mx-auto" dir="rtl">
      {/* Side Arrow Back */}
      <button 
        onClick={onClose}
        className="absolute top-6 right-6 z-[70] w-12 h-12 bg-white/10 backdrop-blur-md rounded-full flex items-center justify-center text-white border border-white/20 active:scale-90 transition-transform shadow-2xl"
      >
        <svg className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover grayscale opacity-70" />
        <div className={`absolute inset-0 border-[15px] transition-all duration-700 pointer-events-none z-10 ${rimColor}`} />

        {/* Capture Button */}
        <div className="absolute bottom-28 inset-x-0 flex justify-center z-20">
          <button 
            onClick={captureAndAnalyze}
            disabled={isAnalyzing}
            className={`w-20 h-20 rounded-full flex items-center justify-center transition-all p-1 border-4 ${isAnalyzing ? 'border-white/20' : 'border-warriorGreen shadow-xl shadow-warriorGreen/30'}`}
          >
            <div className={`w-full h-full rounded-full flex items-center justify-center ${isAnalyzing ? 'bg-white/10' : 'bg-white'}`}>
               {isAnalyzing ? (
                 <div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin" />
               ) : (
                 <div className="w-5 h-5 bg-dark rounded-full"></div>
               )}
            </div>
          </button>
        </div>
      </div>

      {(result || isAnalyzing) && (
        <div className={`absolute bottom-0 inset-x-0 transition-transform duration-500 ease-out z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-120px)]'}`}>
          <div className="bg-white rounded-t-[2.5rem] min-h-[160px] pb-12 border-t-8 border-warriorGreen premium-shadow">
            <button onClick={() => setShowDetails(!showDetails)} className="w-full h-12 flex flex-col items-center justify-center">
              <div className="w-12 h-1 bg-gray-100 rounded-full mb-1" />
              <svg className={`h-6 w-6 text-warriorGreen transition-transform ${showDetails ? 'rotate-180' : 'rotate-0'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 15l7-7 7 7" /></svg>
            </button>

            <div className="px-10 flex justify-between items-center h-12">
               <h3 className="font-black text-dark text-xl uppercase tracking-tighter truncate max-w-[70%]">
                 {isAnalyzing ? 'מנתח מוצר...' : result?.productName}
               </h3>
               <span className={`text-[10px] font-black uppercase px-3 py-1 rounded-full ${result?.isSafe ? 'bg-warriorGreen text-white' : 'bg-red-500 text-white'}`}>
                 {result?.isSafe ? 'SAFE' : 'UNSAFE'}
               </span>
            </div>

            <div className={`px-10 mt-8 space-y-6 transition-opacity duration-300 ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {!result?.isSafe && (
                <div className="space-y-3">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">זוהתה סכנה</p>
                  <div className="flex flex-wrap gap-2">
                    {result?.allergensFound.map(a => (
                      <span key={a} className="px-4 py-2 bg-dark text-warriorGreen text-[10px] font-black uppercase rounded-xl">{a}</span>
                    ))}
                  </div>
                </div>
              )}
              <div className="bg-gray-50 p-6 rounded-2xl border border-black/5">
                <p className="text-dark text-sm leading-relaxed font-bold italic">{result?.summary}</p>
              </div>
              <button 
                onClick={() => { setResult(null); setShowDetails(false); }}
                className="w-full py-4 bg-dark text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all shadow-xl"
              >
                Clear Result
              </button>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-8 rounded-[2.5rem] text-center shadow-2xl z-[80] w-4/5">
          <p className="text-dark font-black mb-6">{error}</p>
          <button onClick={() => setError(null)} className="w-full py-4 bg-dark text-white rounded-2xl font-black text-xs uppercase">סגור</button>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default Scanner;

import React, { useState } from 'react';

interface Props {
  onLogin: (email: string) => void;
}

const Login: React.FC<Props> = ({ onLogin }) => {
  const [email, setEmail] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) onLogin(email);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-8 bg-appBg" dir="rtl">
      <div className="w-full max-w-sm space-y-12 animate-in fade-in zoom-in duration-700">
        <div className="text-center">
          <div className="w-20 h-20 bg-dark rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl -rotate-3 hover:rotate-0 transition-transform">
             <span className="text-4xl font-black text-warriorGreen">W</span>
          </div>
          <h1 className="text-5xl font-black text-dark tracking-tighter uppercase leading-[0.8]">Allergy<br/><span className="text-warriorGreen">Warrior</span></h1>
          <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mt-6">Safety System Protocol</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-dark uppercase tracking-widest px-1">Warrior Identity</label>
            <input
              type="email"
              required
              className="w-full px-6 py-5 rounded-[1.5rem] bg-white border border-black/5 focus:border-warriorGreen focus:ring-4 focus:ring-warriorGreen/10 outline-none transition-all font-bold text-black placeholder-gray-300"
              placeholder="warrior@prot.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <button
            type="submit"
            className="w-full py-5 rounded-[1.5rem] bg-dark text-white font-black text-sm uppercase tracking-widest hover:bg-warriorGreen hover:text-dark active:scale-95 transition-all shadow-xl shadow-dark/10"
          >
            Enter Warrior Mode
          </button>
        </form>

        <p className="text-center text-[9px] text-gray-400 font-bold uppercase tracking-widest opacity-60">
          Advanced Protection • Local Encryption
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { Profile, Group } from '../types';

interface Props {
  profiles: Profile[];
  groups: Group[];
  onAddProfile: (name: string, allergies: string[], groupId?: string) => void;
  onToggleProfile: (id: string) => void;
  onDeleteProfile: (id: string) => void;
  onAddGroup: (name: string) => void;
  onToggleGroup: (id: string) => void;
  onDeleteGroup: (id: string) => void;
}

const COMMON_ALLERGENS = [
  "חלב", "ביצים", "בוטנים", "אגוזים", "סויה", "חיטה", "גלוטן", "שומשום", "דגים", "פירות ים", "חרדל", "סלרי"
];

const ProfileManager: React.FC<Props> = ({ 
  profiles, groups, onAddProfile, onToggleProfile, onDeleteProfile, 
  onAddGroup, onToggleGroup, onDeleteGroup 
}) => {
  const [showAddProfile, setShowAddProfile] = useState(false);
  const [showAddGroup, setShowAddGroup] = useState(false);
  const [newName, setNewName] = useState('');
  const [selectedAllergies, setSelectedAllergies] = useState<string[]>([]);
  const [newGroupName, setNewGroupName] = useState('');
  const [selectedGroupId, setSelectedGroupId] = useState('');

  const handleToggleAllergy = (allergy: string) => {
    setSelectedAllergies(prev => 
      prev.includes(allergy) ? prev.filter(a => a !== allergy) : [...prev, allergy]
    );
  };

  const handleAddProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName && selectedAllergies.length > 0) {
      onAddProfile(newName, selectedAllergies, selectedGroupId || undefined);
      setNewName('');
      setSelectedAllergies([]);
      setSelectedGroupId('');
      setShowAddProfile(false);
    }
  };

  const handleAddGroup = (e: React.FormEvent) => {
    e.preventDefault();
    if (newGroupName) {
      onAddGroup(newGroupName);
      setNewGroupName('');
      setShowAddGroup(false);
    }
  };

  return (
    <div className="space-y-10 py-6 animate-in slide-in-from-right duration-500">
      <div className="px-1">
        <h2 className="text-3xl font-black text-dark tracking-tighter uppercase leading-[0.85] mb-2">Warrior<br/><span className="text-warriorGreen">Profiles</span></h2>
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-widest">ניהול יחידות ופרופילים</p>
      </div>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">קבוצות</h3>
          <button onClick={() => setShowAddGroup(true)} className="text-[10px] font-bold text-white bg-dark px-3 py-1.5 rounded-full uppercase">Add Group</button>
        </div>

        <div className="space-y-3">
          {showAddGroup && (
            <form onSubmit={handleAddGroup} className="bg-white p-6 rounded-[2rem] border border-black/5 premium-shadow space-y-4 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm"
                placeholder="שם הקבוצה"
                value={newGroupName}
                onChange={e => setNewGroupName(e.target.value)}
              />
              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-dark text-white py-3 rounded-xl text-xs font-black uppercase">שמור</button>
                <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-3 text-gray-400 text-xs font-bold uppercase">ביטול</button>
              </div>
            </form>
          )}
          {groups.map(group => (
            <div key={group.id} className="bg-white p-4 rounded-2xl border border-black/5 flex items-center justify-between island-shadow">
              <div className="flex items-center gap-3">
                <div className={`w-2 h-2 rounded-full ${group.enabled ? 'bg-warriorGreen' : 'bg-gray-200'}`} />
                <span className={`font-black text-sm uppercase tracking-tight ${group.enabled ? 'text-dark' : 'text-gray-300'}`}>{group.name}</span>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${group.enabled ? 'bg-warriorGreen/10 text-warriorDarkGreen' : 'bg-gray-50 text-gray-400'}`}>
                  {group.enabled ? 'Active' : 'Off'}
                </button>
                <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-200 hover:text-red-500">
                  <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">פרופילים</h3>
          <button onClick={() => setShowAddProfile(true)} className="text-[10px] font-bold text-dark bg-warriorGreen px-3 py-1.5 rounded-full uppercase">Add Profile</button>
        </div>

        <div className="space-y-4">
          {showAddProfile && (
            <form onSubmit={handleAddProfile} className="bg-white p-6 rounded-[2.5rem] border border-black/5 premium-shadow space-y-6 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm"
                placeholder="שם הפרופיל"
                value={newName}
                onChange={e => setNewName(e.target.value)}
              />

              <div className="space-y-3">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Select Allergies</label>
                <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto pr-2 hide-scrollbar">
                  {COMMON_ALLERGENS.map(allergy => (
                    <label key={allergy} className={`flex items-center gap-3 p-3 rounded-xl border transition-all cursor-pointer ${selectedAllergies.includes(allergy) ? 'bg-dark border-dark text-warriorGreen' : 'bg-gray-50 border-transparent text-gray-400 font-bold'}`}>
                      <input type="checkbox" className="hidden" checked={selectedAllergies.includes(allergy)} onChange={() => handleToggleAllergy(allergy)} />
                      <span className="text-xs font-black uppercase tracking-tight">{allergy}</span>
                    </label>
                  ))}
                </div>
              </div>

              <select className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" value={selectedGroupId} onChange={e => setSelectedGroupId(e.target.value)}>
                <option value="">ללא קבוצה</option>
                {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
              </select>

              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-warriorGreen text-dark py-4 rounded-xl text-xs font-black uppercase tracking-widest">Create Profile</button>
                <button type="button" onClick={() => setShowAddProfile(false)} className="px-4 py-4 text-gray-400 text-xs font-bold uppercase">Cancel</button>
              </div>
            </form>
          )}

          {profiles.map(profile => {
            const group = groups.find(g => g.id === profile.groupId);
            const isGroupDisabled = group && !group.enabled;
            const effectiveEnabled = profile.enabled && !isGroupDisabled;

            return (
              <div key={profile.id} className={`bg-white p-6 rounded-[2rem] border island-shadow transition-all ${effectiveEnabled ? 'border-black/5' : 'opacity-40 grayscale'}`}>
                <div className="flex justify-between items-start mb-6">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${effectiveEnabled ? 'bg-dark text-warriorGreen' : 'bg-gray-100 text-gray-300'}`}>
                      {profile.name[0].toUpperCase()}
                    </div>
                    <div>
                      <p className="font-black text-dark text-lg uppercase tracking-tight leading-none">{profile.name}</p>
                      {group && <p className="text-[9px] text-warriorGreen font-black uppercase mt-1">Group: {group.name}</p>}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${profile.enabled ? 'bg-warriorGreen text-dark' : 'bg-gray-100 text-gray-400'}`}>
                      {profile.enabled ? 'ON' : 'OFF'}
                    </button>
                    <button onClick={() => onDeleteProfile(profile.id)} className="p-1 text-gray-200 hover:text-red-500">
                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                  </div>
                </div>
                <div className="flex flex-wrap gap-1.5">
                  {profile.allergies.map(a => (
                    <span key={a} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${effectiveEnabled ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-300'}`}>{a}</span>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

export default ProfileManager;

