import { Profile, Group, HistoryItem } from '../types';

interface UserData {
  profiles: Profile[];
  groups: Group[];
  history: HistoryItem[];
}

export const db = {
  getStorageKey(email: string) {
    return `allergy_warrior_db_${email.toLowerCase()}`;
  },

  saveUserData(email: string, data: UserData) {
    const key = this.getStorageKey(email);
    localStorage.setItem(key, JSON.stringify(data));
  },

  getUserData(email: string): UserData {
    const key = this.getStorageKey(email);
    const saved = localStorage.getItem(key);
    if (saved) {
      return JSON.parse(saved);
    }
    return {
      profiles: [],
      groups: [],
      history: []
    };
  }
};

import React, { useState, useEffect } from 'react';
import { User, Profile, Group, HistoryItem } from './types';
import { db } from './services/db';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import ProfileManager from './components/ProfileManager';
import Scanner from './components/Scanner';
import History from './components/History';
import Account from './components/Account';
import Navigation from './components/Navigation';

type View = 'dashboard' | 'profiles' | 'scan' | 'history' | 'account';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<View>('dashboard');
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // On Login: Load user-specific data
  useEffect(() => {
    const savedEmail = localStorage.getItem('current_warrior_email');
    if (savedEmail) {
      const userData = db.getUserData(savedEmail);
      setUser({ email: savedEmail });
      setProfiles(userData.profiles);
      setGroups(userData.groups);
      setHistory(userData.history);
    }
  }, []);

  // On any change: Save user-specific data to our "database"
  useEffect(() => {
    if (user) {
      db.saveUserData(user.email, { profiles, groups, history });
    }
  }, [user, profiles, groups, history]);

  const handleLogin = (email: string) => {
    const userData = db.getUserData(email);
    setUser({ email });
    setProfiles(userData.profiles);
    setGroups(userData.groups);
    setHistory(userData.history);
    localStorage.setItem('current_warrior_email', email);
  };

  const handleLogout = () => {
    setUser(null);
    setProfiles([]);
    setGroups([]);
    setHistory([]);
    localStorage.removeItem('current_warrior_email');
  };

  const addProfile = (name: string, allergies: string[], groupId?: string) => {
    const newProfile: Profile = {
      id: crypto.randomUUID(),
      name,
      allergies,
      enabled: true,
      groupId
    };
    setProfiles(prev => [...prev, newProfile]);
  };

  const toggleProfile = (id: string) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, enabled: !p.enabled } : p));
  };

  const deleteProfile = (id: string) => {
    setProfiles(prev => prev.filter(p => p.id !== id));
  };

  const addGroup = (name: string) => {
    const newGroup: Group = { id: crypto.randomUUID(), name, enabled: true };
    setGroups(prev => [...prev, newGroup]);
  };

  const toggleGroup = (id: string) => {
    setGroups(prev => prev.map(g => g.id === id ? { ...g, enabled: !g.enabled } : g));
  };

  const deleteGroup = (id: string) => {
    setGroups(prev => prev.filter(g => g.id !== id));
    setProfiles(prev => prev.map(p => p.groupId === id ? { ...p, groupId: undefined } : p));
  };

  const addToHistory = (item: Omit<HistoryItem, 'id' | 'timestamp'>) => {
    const newItem: HistoryItem = {
      ...item,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
    };
    setHistory(prev => [newItem, ...prev].slice(0, 50));
  };

  const activeAllergens = Array.from(new Set(
    profiles
      .filter(p => {
        if (!p.enabled) return false;
        if (p.groupId) {
          const group = groups.find(g => g.id === p.groupId);
          return group?.enabled ?? true;
        }
        return true;
      })
      .flatMap(p => p.allergies)
  ));

  const activeCount = activeAllergens.length;

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-appBg pb-24 relative max-w-md mx-auto flex flex-col shadow-2xl overflow-x-hidden" dir="rtl">
      {/* Small Island Header */}
      <div className="fixed top-4 left-0 right-0 z-50 px-4 max-w-md mx-auto pointer-events-none">
        <div className="bg-white island-shadow border border-black/5 rounded-full py-2 px-4 flex items-center justify-between pointer-events-auto">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-warriorGreen rounded-full flex items-center justify-center font-black text-white text-[10px]">W</div>
            <span className="text-xs font-black text-dark uppercase tracking-tighter">Allergy Warrior</span>
          </div>
          <div className="flex items-center gap-3">
            <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[10px] font-bold ${activeCount > 0 ? 'bg-warriorGreen/10 border-warriorGreen/20 text-warriorDarkGreen' : 'bg-gray-100 border-gray-200 text-gray-400'}`}>
              <div className={`w-1.5 h-1.5 rounded-full ${activeCount > 0 ? 'bg-warriorGreen animate-pulse' : 'bg-gray-400'}`} />
              <span>אלרגיות: {activeCount}</span>
            </div>
            <div className="w-8 h-8 bg-gray-50 border border-black/5 rounded-full flex items-center justify-center text-[10px] font-bold text-dark">
              {user.email[0].toUpperCase()}
            </div>
          </div>
        </div>
      </div>

      <main className="flex-1 mt-16 px-4 py-4 overflow-y-auto">
        {view === 'dashboard' && (
          <Dashboard 
            history={history} 
            onNavigate={() => setView('scan')} 
            activeCount={activeCount}
          />
        )}
        {view === 'profiles' && (
          <ProfileManager 
            profiles={profiles} 
            groups={groups} 
            onAddProfile={addProfile}
            onToggleProfile={toggleProfile}
            onDeleteProfile={deleteProfile}
            onAddGroup={addGroup}
            onToggleGroup={toggleGroup}
            onDeleteGroup={deleteGroup}
          />
        )}
        {view === 'scan' && (
          <Scanner 
            activeAllergens={activeAllergens.length > 0 ? activeAllergens : []} 
            onScanComplete={addToHistory}
            onClose={() => setView('dashboard')}
          />
        )}
        {view === 'history' && (
          <History history={history} />
        )}
        {view === 'account' && (
          <Account user={user} onLogout={handleLogout} profilesCount={profiles.length} historyCount={history.length} />
        )}
      </main>

      <Navigation currentView={view} setView={setView} />
    </div>
  );
}

import React, { useState } from 'react';
import { Profile, Group } from '../types';

interface Props {
  profiles: Profile[];
  groups: Group[];
  onAddProfile: (name: string, allergies: string[], groupId?: string) => void;
  onToggleProfile: (id: string) => void;
  onDeleteProfile: (id: string) => void;
  onAddGroup: (name: string) => void;
  onToggleGroup: (id: string) => void;
  onDeleteGroup: (id: string) => void;
}

const COMMON_ALLERGENS = [
  "חלב", "ביצים", "בוטנים", "אגוזים", "סויה", "חיטה", "גלוטן", "שומשום", "דגים", "פירות ים", "חרדל", "סלרי"
];

const ProfileManager: React.FC<Props> = ({ 
  profiles, groups, onAddProfile, onToggleProfile, onDeleteProfile, 
  onAddGroup, onToggleGroup, onDeleteGroup 
}) => {
  const [showAddProfile, setShowAddProfile] = useState(false);
  const [showAddGroup, setShowAddGroup] = useState(false);
  const [newName, setNewName] = useState('');
  const [selectedAllergies, setSelectedAllergies] = useState<string[]>([]);
  const [newGroupName, setNewGroupName] = useState('');
  const [selectedGroupId, setSelectedGroupId] = useState('');
  const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

  const handleToggleAllergy = (allergy: string) => {
    setSelectedAllergies(prev => 
      prev.includes(allergy) ? prev.filter(a => a !== allergy) : [...prev, allergy]
    );
  };

  const handleAddProfile = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName && selectedAllergies.length > 0) {
      onAddProfile(newName, selectedAllergies, selectedGroupId || undefined);
      setNewName('');
      setSelectedAllergies([]);
      setSelectedGroupId('');
      setShowAddProfile(false);
    }
  };

  const handleAddGroup = (e: React.FormEvent) => {
    e.preventDefault();
    if (newGroupName) {
      onAddGroup(newGroupName);
      setNewGroupName('');
      setShowAddGroup(false);
    }
  };

  const toggleGroupCollapse = (groupId: string) => {
    setCollapsedGroups(prev => {
      const next = new Set(prev);
      if (next.has(groupId)) {
        next.delete(groupId);
      } else {
        next.add(groupId);
      }
      return next;
    });
  };

  const renderProfileCard = (profile: Profile) => {
    const group = groups.find(g => g.id === profile.groupId);
    const isGroupDisabled = group && !group.enabled;
    const effectiveEnabled = profile.enabled && !isGroupDisabled;

    return (
      <div key={profile.id} className={`bg-white p-5 rounded-[2rem] border island-shadow transition-all relative ${effectiveEnabled ? 'border-black/5' : 'opacity-40 grayscale'}`}>
        <div className="flex justify-between items-start">
           <button onClick={() => onDeleteProfile(profile.id)} className="text-gray-200 hover:text-red-500 transition-colors p-1 mt-1">
            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
          </button>

          <div className="flex-1 flex flex-col items-end">
            <div className="flex items-center gap-3 mb-1">
              <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${profile.enabled ? 'bg-warriorGreen text-white' : 'bg-gray-100 text-gray-400'}`}>
                {profile.enabled ? 'ON' : 'OFF'}
              </button>
              <h4 className="font-black text-dark text-lg uppercase tracking-tight">{profile.name}</h4>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black text-lg ${effectiveEnabled ? 'bg-dark text-warriorGreen' : 'bg-gray-100 text-gray-300'}`}>
                {profile.name[0].toUpperCase()}
              </div>
            </div>

            <div className="flex flex-wrap gap-1.5 justify-end mt-2">
              {profile.allergies.map(a => (
                <span key={a} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${effectiveEnabled ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-300'}`}>{a}</span>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-10 py-6 animate-in slide-in-from-right duration-500">
      <div className="px-1">
        <h2 className="text-3xl font-black text-dark tracking-tighter uppercase leading-[0.85] mb-2">Allergy Warrior<br/><span className="text-warriorGreen">Profiles</span></h2>
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-widest">ניהול יחידות ופרופילים</p>
      </div>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">קבוצות</h3>
          <button 
            onClick={() => setShowAddGroup(true)} 
            className="w-8 h-8 flex items-center justify-center bg-dark text-white rounded-full transition-transform active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          </button>
        </div>

        <div className="space-y-3">
          {showAddGroup && (
            <form onSubmit={handleAddGroup} className="bg-white p-6 rounded-[2rem] border border-black/5 premium-shadow space-y-4 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm"
                placeholder="שם הקבוצה"
                value={newGroupName}
                onChange={e => setNewGroupName(e.target.value)}
              />
              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-dark text-white py-3 rounded-xl text-xs font-black uppercase">שמור</button>
                <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-3 text-gray-400 text-xs font-bold uppercase">ביטול</button>
              </div>
            </form>
          )}

          {groups.map(group => {
            const isCollapsed = collapsedGroups.has(group.id);
            const nestedProfiles = profiles.filter(p => p.groupId === group.id);

            return (
              <div key={group.id} className="space-y-3">
                <div 
                  className="bg-white p-4 rounded-2xl border border-black/5 flex items-center justify-between island-shadow cursor-pointer active:scale-[0.98] transition-all"
                  onClick={() => toggleGroupCollapse(group.id)}
                >
                  <div className="flex items-center gap-2" onClick={(e) => e.stopPropagation()}>
                    <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-200 hover:text-red-500 transition-colors">
                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                    </button>
                    <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${group.enabled ? 'bg-warriorGreen/10 text-warriorDarkGreen' : 'bg-gray-50 text-gray-400'}`}>
                      {group.enabled ? 'Active' : 'Off'}
                    </button>
                  </div>
                  <div className="flex items-center gap-3">
                    <span className={`font-black text-sm uppercase tracking-tight ${group.enabled ? 'text-dark' : 'text-gray-300'}`}>{group.name}</span>
                    <svg className={`h-4 w-4 text-gray-400 transition-transform ${isCollapsed ? '' : 'rotate-180'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                    </svg>
                    <div className={`w-2 h-2 rounded-full ${group.enabled ? 'bg-warriorGreen' : 'bg-gray-200'}`} />
                  </div>
                </div>

                {/* Branching Profiles - Collapsible */}
                {!isCollapsed && nestedProfiles.length > 0 && (
                  <div className="pr-6 space-y-3 relative animate-in slide-in-from-top duration-300">
                    <div className="absolute top-0 bottom-0 right-3 w-0.5 bg-gray-100 rounded-full" />
                    {nestedProfiles.map(renderProfileCard)}
                  </div>
                )}
                {!isCollapsed && nestedProfiles.length === 0 && (
                   <p className="text-center text-[8px] font-black text-gray-300 uppercase py-2">קבוצה ריקה</p>
                )}
              </div>
            );
          })}
        </div>
      </section>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">פרופילים אישיים</h3>
          <button 
            onClick={() => setShowAddProfile(true)} 
            className="w-8 h-8 flex items-center justify-center bg-warriorGreen text-dark rounded-full transition-transform active:scale-90"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          </button>
        </div>

        <div className="space-y-4">
          {showAddProfile && (
            <form onSubmit={handleAddProfile} className="bg-white p-6 rounded-[2.5rem] border border-black/5 premium-shadow space-y-6 animate-in zoom-in duration-200">
              <input
                autoFocus
                className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm"
                placeholder="שם הפרופיל"
                value={newName}
                onChange={e => setNewName(e.target.value)}
              />

              <div className="space-y-3">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Select Allergies</label>
                <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto pr-2 hide-scrollbar">
                  {COMMON_ALLERGENS.map(allergy => (
                    <label key={allergy} className={`flex items-center gap-3 p-3 rounded-xl border transition-all cursor-pointer ${selectedAllergies.includes(allergy) ? 'bg-dark border-dark text-warriorGreen' : 'bg-gray-50 border-transparent text-gray-400 font-bold'}`}>
                      <input type="checkbox" className="hidden" checked={selectedAllergies.includes(allergy)} onChange={() => handleToggleAllergy(allergy)} />
                      <span className="text-xs font-black uppercase tracking-tight">{allergy}</span>
                    </label>
                  ))}
                </div>
              </div>

              <select className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" value={selectedGroupId} onChange={e => setSelectedGroupId(e.target.value)}>
                <option value="">ללא קבוצה</option>
                {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
              </select>

              <div className="flex gap-2">
                <button type="submit" className="flex-1 bg-warriorGreen text-dark py-4 rounded-xl text-xs font-black uppercase tracking-widest">Create Profile</button>
                <button type="button" onClick={() => setShowAddProfile(false)} className="px-4 py-4 text-gray-400 text-xs font-bold uppercase">Cancel</button>
              </div>
            </form>
          )}

          {profiles.filter(p => !p.groupId).map(renderProfileCard)}
        </div>
      </section>
    </div>
  );
};

