import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "האם המוצר בטוח לצריכה",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "רשימת אלרגנים שנמצאו בעברית",
    },
    summary: {
      type: Type.STRING,
      description: "הסבר קצר ותמציתי בעברית",
    },
  },
  required: ["productName", "isSafe", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Analyze this food product for these specific allergens: ${activeAllergens.join(", ")}.

    ${input.text ? `PRODUCT SEARCH QUERY: ${input.text}` : "IMAGE IDENTIFICATION: Identify the product from the image. Look for brand names, product titles, ingredient lists, or barcodes."}

    CRITICAL RULES:
    1. PRIORITIZE human safety. If ANY ingredient or "may contain" traces match the allergens list, isSafe must be FALSE.
    2. RESPOND IN HEBREW.
    3. isSafe: FALSE if ANY allergen or hidden traces found.
    4. summary: Provide a one-sentence safety explanation in Hebrew.
    5. Be extremely concise.
    6. If a barcode is visible, use it to identify the product accurately.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0, // Deterministic results for safety
    },
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("שגיאה בניתוח הנתונים מהשרת. נסה שוב.");
  }
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setError(null);
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { 
          facingMode: 'environment',
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      setError("גישה למצלמה נכשלה. אנא וודא הרשאות.");
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;
    const context = canvasRef.current.getContext('2d');
    if (!context) return;

    // Smooth frame capture
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);

    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.8).split(',')[1];
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError("אין אלרגיות פעילות. אנא הגדר פרופילים.");
      return;
    }
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(true); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        allergensFound: analysis.allergensFound,
      });
    } catch (err) {
      setError("שגיאה בניתוח התמונה");
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const rimColor = isAnalyzing 
    ? 'border-white animate-pulse' 
    : result 
      ? result.isSafe ? 'border-warriorGreen shadow-[inset_0_0_120px_rgba(34,197,94,0.4)]' : 'border-red-500 shadow-[inset_0_0_120px_rgba(239,68,68,0.4)]'
      : 'border-transparent';

  return (
    <div className="fixed inset-0 z-[60] bg-black overflow-hidden flex flex-col max-w-md mx-auto" dir="rtl">
      {/* Back Button */}
      <button 
        onClick={onClose}
        className="absolute top-8 right-8 z-[70] w-12 h-12 bg-black/40 backdrop-blur-xl rounded-full flex items-center justify-center text-white border border-white/10 active:scale-90 transition-transform shadow-2xl"
      >
        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
      </button>

      {/* Viewfinder */}
      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
        <div className={`absolute inset-0 border-[12px] transition-all duration-1000 pointer-events-none z-10 ${rimColor}`} />

        {/* Scanning Animation */}
        {!result && !isAnalyzing && (
          <div className="absolute inset-x-12 top-1/2 -translate-y-1/2 h-0.5 bg-warriorGreen/50 shadow-[0_0_15px_#22c55e] animate-bounce pointer-events-none" />
        )}

        {/* Capture Button Container */}
        <div className="absolute bottom-32 inset-x-0 flex justify-center z-20">
          <button 
            onClick={captureAndAnalyze}
            disabled={isAnalyzing}
            className={`w-24 h-24 rounded-full flex items-center justify-center transition-all p-1.5 border-4 ${isAnalyzing ? 'border-white/10' : 'border-warriorGreen shadow-2xl shadow-warriorGreen/40'}`}
          >
            <div className={`w-full h-full rounded-full flex items-center justify-center ${isAnalyzing ? 'bg-white/10' : 'bg-white'}`}>
               {isAnalyzing ? (
                 <div className="w-10 h-10 border-4 border-white border-t-transparent rounded-full animate-spin" />
               ) : (
                 <div className="w-6 h-6 bg-dark rounded-full"></div>
               )}
            </div>
          </button>
        </div>
      </div>

      {/* Results Drawer */}
      {(result || isAnalyzing) && (
        <div className={`absolute bottom-0 inset-x-0 transition-transform duration-500 ease-out z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-120px)]'}`}>
          <div className="bg-white rounded-t-[3rem] min-h-[180px] pb-14 border-t-8 border-warriorGreen premium-shadow">
            <button onClick={() => setShowDetails(!showDetails)} className="w-full h-12 flex flex-col items-center justify-center">
              <div className="w-16 h-1 bg-gray-100 rounded-full mb-1" />
              <svg className={`h-6 w-6 text-warriorGreen transition-transform ${showDetails ? 'rotate-180' : 'rotate-0'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
            </button>

            <div className="px-10 flex justify-between items-center h-14">
               <h3 className="font-black text-dark text-xl uppercase tracking-tighter truncate max-w-[70%]">
                 {isAnalyzing ? 'מזהה מוצר...' : result?.productName}
               </h3>
               <span className={`text-[10px] font-black uppercase px-4 py-1.5 rounded-full ${result?.isSafe ? 'bg-warriorGreen text-white' : 'bg-red-500 text-white'}`}>
                 {result?.isSafe ? 'בטוח' : 'מסוכן'}
               </span>
            </div>

            <div className={`px-10 mt-8 space-y-6 transition-opacity duration-300 ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {!result?.isSafe && result?.allergensFound.length ? (
                <div className="space-y-3">
                  <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">זוהו רכיבים אסורים:</p>
                  <div className="flex flex-wrap gap-2">
                    {result?.allergensFound.map(a => (
                      <span key={a} className="px-4 py-2 bg-dark text-warriorGreen text-[11px] font-black uppercase rounded-2xl border border-warriorGreen/10">{a}</span>
                    ))}
                  </div>
                </div>
              ) : null}

              <div className="bg-gray-50 p-6 rounded-3xl border border-black/5">
                <p className="text-dark text-sm font-bold leading-relaxed">{isAnalyzing ? 'סורק רכיבים ומזהה מותג...' : result?.summary}</p>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => { setResult(null); setShowDetails(false); }}
                  className="flex-1 py-5 bg-dark text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all shadow-xl"
                >
                  נקה תוצאה
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-10 rounded-[3rem] text-center shadow-2xl z-[80] w-[85%] border-t-8 border-red-500">
          <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </div>
          <p className="text-dark font-black mb-8 text-lg">{error}</p>
          <button onClick={() => setError(null)} className="w-full py-5 bg-dark text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl">הבנתי</button>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

