import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "האם המוצר בטוח לצריכה",
    },
    isEdible: {
      type: Type.BOOLEAN,
      description: "האם מדובר במוצר מזון/אכיל",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "רשימת אלרגנים שנמצאו בעברית",
    },
    summary: {
      type: Type.STRING,
      description: "הסבר קצר ותמציתי בעברית",
    },
  },
  required: ["productName", "isSafe", "isEdible", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  const prompt = `
    Analyze this item for these specific allergens: ${activeAllergens.join(", ")}.

    ${input.text ? `PRODUCT SEARCH QUERY: ${input.text}` : "IMAGE IDENTIFICATION: Identify the item from the image."}

    CRITICAL RULES:
    1. First, determine if the item is EDIBLE (food/drink/consumable). If it's a non-food item (electronics, cleaning supplies, tools, etc.), set isEdible to false.
    2. If isEdible is false, allergens found should be empty and isSafe should be false.
    3. If isEdible is true, PRIORITIZE human safety. If ANY ingredient or "may contain" traces match the allergens list, isSafe must be FALSE.
    4. RESPOND IN HEBREW.
    5. summary: Provide a one-sentence safety explanation in Hebrew. If not edible, say "זה אינו מוצר אכיל, אנא נסה שוב".
    6. Be extremely concise.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0,
    },
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("שגיאה בניתוח הנתונים מהשרת. נסה שוב.");
  }
}

