import React, { useState, useRef, useEffect, useCallback } from 'react';
import { analyzeProduct } from '../services/geminiService';
import { AnalysisResult, HistoryItem } from '../types';

interface Props {
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
  onClose?: () => void;
}

const Scanner: React.FC<Props> = ({ activeAllergens, onScanComplete, onClose }) => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalysisResult | null>(null);
  const [showDetails, setShowDetails] = useState(false);
  const [error, setError] = useState<{ title: string; message: string; action: string } | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startCamera = async () => {
    try {
      setError(null);
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) throw new Error('NotSupportedError');
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err: any) {
      setError({
        title: "תקלה בגישה למצלמה",
        message: "לא הצלחנו להפעיל את המצלמה שלך. בדוק את הגדרות הפרטיות.",
        action: "נסה לרענן את הדף"
      });
    }
  };

  const stopCamera = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
  }, []);

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || isAnalyzing) return;
    const context = canvasRef.current.getContext('2d');
    if (!context) return;
    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0, canvasRef.current.width, canvasRef.current.height);
    const base64Image = canvasRef.current.toDataURL('image/jpeg', 0.8).split(',')[1];
    await performAnalysis({ imageBase64: base64Image });
  };

  const performAnalysis = async (input: { text?: string; imageBase64?: string }) => {
    if (activeAllergens.length === 0) {
      setError({ title: "אין אלרגיות", message: "הגדר לפחות אלרגיה אחת בפרופיל.", action: "חזור לפרופילים" });
      return;
    }
    setIsAnalyzing(true);
    setError(null);
    try {
      const analysis = await analyzeProduct(input, activeAllergens);
      setResult(analysis);
      setShowDetails(true); 
      onScanComplete({
        productName: analysis.productName,
        isSafe: analysis.isSafe,
        isEdible: analysis.isEdible,
        allergensFound: analysis.allergensFound,
      });
    } catch (err) {
      setError({ title: "שגיאת ניתוח", message: "לא הצלחנו לקרוא את רשימת הרכיבים.", action: "נסה לצלם שוב" });
    } finally {
      setIsAnalyzing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  const rimColor = isAnalyzing 
    ? 'border-white animate-pulse' 
    : result 
      ? !result.isEdible 
        ? 'border-white shadow-[inset_0_0_120px_rgba(255,255,255,0.4)]'
        : result.isSafe ? 'border-warriorGreen shadow-[inset_0_0_120px_rgba(34,197,94,0.4)]' : 'border-red-500 shadow-[inset_0_0_120px_rgba(239,68,68,0.4)]'
      : 'border-transparent';

  return (
    <div className="fixed inset-0 z-[60] bg-black overflow-hidden flex flex-col max-w-md mx-auto" dir="rtl">
      <button onClick={onClose} className="absolute top-8 right-8 z-[70] w-12 h-12 bg-black/40 backdrop-blur-xl rounded-full flex items-center justify-center text-white border border-white/10 active:scale-90 transition-transform shadow-2xl">
        <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" /></svg>
      </button>

      <div className="flex-1 relative">
        <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
        <div className={`absolute inset-0 border-[12px] transition-all duration-1000 pointer-events-none z-10 ${rimColor}`} />
        {!result && !isAnalyzing && !error && <div className="absolute inset-x-12 top-1/2 -translate-y-1/2 h-0.5 bg-warriorGreen/50 shadow-[0_0_15px_#22c55e] animate-bounce pointer-events-none" />}
        {!error && !result && (
          <div className="absolute bottom-32 inset-x-0 flex justify-center z-20">
            <button onClick={captureAndAnalyze} disabled={isAnalyzing} className={`w-24 h-24 rounded-full flex items-center justify-center transition-all p-1.5 border-4 ${isAnalyzing ? 'border-white/10' : 'border-warriorGreen'}`}>
              <div className={`w-full h-full rounded-full flex items-center justify-center ${isAnalyzing ? 'bg-white/10' : 'bg-white'}`}>
                 {isAnalyzing ? <div className="w-10 h-10 border-4 border-white border-t-transparent rounded-full animate-spin" /> : <div className="w-6 h-6 bg-dark rounded-full"></div>}
              </div>
            </button>
          </div>
        )}
      </div>

      {(result || isAnalyzing) && (
        <div className={`absolute bottom-0 inset-x-0 transition-transform duration-500 ease-out z-30 ${showDetails ? 'translate-y-0' : 'translate-y-[calc(100%-120px)]'}`}>
          <div className={`bg-white rounded-t-[3rem] min-h-[180px] pb-14 border-t-8 premium-shadow ${result && !result.isEdible ? 'border-white' : 'border-warriorGreen'}`}>
            <button onClick={() => setShowDetails(!showDetails)} className="w-full h-12 flex flex-col items-center justify-center">
              <div className="w-16 h-1 bg-gray-100 rounded-full mb-1" />
              <svg className={`h-6 w-6 transition-transform ${showDetails ? 'rotate-180' : 'rotate-0'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
            </button>

            <div className="px-10 flex justify-between items-center h-14">
               <h3 className="font-black text-dark text-xl uppercase tracking-tighter truncate max-w-[70%]">
                 {isAnalyzing ? 'מנתח מוצר...' : result?.productName}
               </h3>
               <span className={`text-[10px] font-black uppercase px-4 py-1.5 rounded-full ${result ? (!result.isEdible ? 'bg-gray-400 text-white' : result.isSafe ? 'bg-warriorGreen text-white' : 'bg-red-500 text-white') : 'bg-gray-100'}`}>
                 {result ? (!result.isEdible ? 'לא אכיל' : result.isSafe ? 'בטוח' : 'מסוכן') : '...'}
               </span>
            </div>

            <div className={`px-10 mt-8 space-y-6 transition-opacity duration-300 ${showDetails ? 'opacity-100' : 'opacity-0'}`}>
              {result && !result.isEdible ? (
                <div className="bg-gray-50 p-8 rounded-3xl border border-black/5 text-center">
                   <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 border border-black/5">
                      <svg className="w-8 h-8 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                   </div>
                   <p className="text-dark text-lg font-black leading-tight mb-2">זה אינו מוצר אכיל</p>
                   <p className="text-gray-400 font-bold text-xs uppercase tracking-widest">אנא נסה לסרוק מוצר מזון</p>
                </div>
              ) : (
                <>
                  {!result?.isSafe && result?.allergensFound.length ? (
                    <div className="space-y-3">
                      <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">רכיבים מסוכנים:</p>
                      <div className="flex flex-wrap gap-2">
                        {result?.allergensFound.map(a => (
                          <span key={a} className="px-4 py-2 bg-dark text-warriorGreen text-[11px] font-black uppercase rounded-2xl border border-warriorGreen/10">{a}</span>
                        ))}
                      </div>
                    </div>
                  ) : null}
                  <div className="bg-gray-50 p-6 rounded-3xl border border-black/5">
                    <p className="text-dark text-sm font-bold leading-relaxed">{isAnalyzing ? 'בודק התאמה לפרופיל...' : result?.summary}</p>
                  </div>
                </>
              )}
              <div className="flex gap-3">
                <button onClick={() => { setResult(null); setShowDetails(false); }} className="flex-1 py-5 bg-dark text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all shadow-xl">
                  נקה וסרוק שוב
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {error && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-10 rounded-[3rem] text-center shadow-2xl z-[80] w-[85%] border-t-8 border-red-500">
          <h3 className="text-xl font-black text-dark mb-2 tracking-tight">{error.title}</h3>
          <p className="text-gray-500 font-bold mb-8 text-sm">{error.message}</p>
          <button onClick={() => { setError(null); startCamera(); }} className="w-full py-5 bg-dark text-white rounded-2xl font-black text-xs uppercase shadow-xl">נסה שוב</button>
        </div>
      )}
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default Scanner;

import React, { useState } from 'react';
import { HistoryItem, AnalysisResult } from '../types';
import { analyzeProduct } from '../services/geminiService';

interface Props {
  history: HistoryItem[];
  onNavigate: () => void;
  activeAllergens: string[];
  onScanComplete: (item: Omit<HistoryItem, 'id' | 'timestamp'>) => void;
}

const Dashboard: React.FC<Props> = ({ history, onNavigate, activeAllergens, onScanComplete }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [searchResult, setSearchResult] = useState<AnalysisResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const safeHistory = history.filter(h => h.isSafe && h.isEdible);
  const activeCount = activeAllergens.length;

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!searchQuery.trim()) return;
    if (activeAllergens.length === 0) {
      setError("אנא הגדר אלרגיות בפרופילים לפני החיפוש");
      return;
    }
    setIsSearching(true);
    setError(null);
    try {
      const result = await analyzeProduct({ text: searchQuery }, activeAllergens);
      setSearchResult(result);
      onScanComplete({
        productName: result.productName,
        isSafe: result.isSafe,
        isEdible: result.isEdible,
        allergensFound: result.allergensFound,
      });
    } catch (err) {
      setError("שגיאה בחיפוש המוצר. נסה שוב.");
    } finally {
      setIsSearching(false);
    }
  };

  return (
    <div className="space-y-8 py-6 animate-in slide-in-from-bottom duration-500">
      <div className="px-1">
        <h2 className="text-3xl font-black text-dark tracking-tighter uppercase leading-[0.85] mb-2">My<br/><span className="text-warriorGreen">Products</span></h2>
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-widest">חיפוש וסריקת מוצרים בטוחים</p>
      </div>

      <div className="px-1">
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            className="w-full px-6 py-5 rounded-[2rem] bg-white border border-black/5 focus:border-warriorGreen outline-none transition-all font-bold text-black placeholder-gray-300 premium-shadow pr-14"
            placeholder="חפש מוצר, מותג או רכיבים..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            disabled={isSearching}
          />
          <button type="submit" className="absolute left-3 top-1/2 -translate-y-1/2 w-12 h-12 bg-dark text-white rounded-2xl flex items-center justify-center">
            {isSearching ? <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin" /> : <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>}
          </button>
        </form>
      </div>

      {searchResult && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-dark/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className={`bg-white w-full max-w-sm rounded-[3rem] overflow-hidden shadow-2xl animate-in zoom-in border-b-8 ${!searchResult.isEdible ? 'border-white' : 'border-warriorGreen'}`}>
            <div className="p-8 space-y-6">
              <div className="flex justify-between items-start gap-4">
                <h3 className="text-2xl font-black text-dark uppercase tracking-tighter leading-none flex-1 truncate">{searchResult.productName}</h3>
                <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${!searchResult.isEdible ? 'bg-gray-400 text-white' : searchResult.isSafe ? 'bg-warriorGreen text-white' : 'bg-red-500 text-white'}`}>
                  {!searchResult.isEdible ? 'לא אכיל' : searchResult.isSafe ? 'בטוח' : 'מסוכן'}
                </span>
              </div>

              {!searchResult.isEdible ? (
                 <div className="bg-gray-50 p-8 rounded-3xl border border-black/5 text-center">
                    <p className="text-dark text-lg font-black leading-tight mb-2">זה אינו מוצר אכיל</p>
                    <p className="text-gray-400 font-bold text-xs uppercase tracking-widest">אנא נסה שוב עם מוצר מזון</p>
                 </div>
              ) : (
                <>
                  {!searchResult.isSafe && (
                    <div className="space-y-3">
                      <p className="text-[10px] font-black text-red-500 uppercase tracking-widest">אלרגן זוהה:</p>
                      <div className="flex flex-wrap gap-2">
                        {searchResult.allergensFound.map(a => (<span key={a} className="px-3 py-1.5 bg-red-50 text-red-600 text-[10px] font-black rounded-xl">{a}</span>))}
                      </div>
                    </div>
                  )}
                  <div className="bg-gray-50 p-6 rounded-3xl border border-black/5"><p className="text-dark text-sm font-bold leading-relaxed">{searchResult.summary}</p></div>
                </>
              )}

              <button onClick={() => setSearchResult(null)} className="w-full py-5 bg-dark text-white rounded-2xl font-black text-xs uppercase active:scale-95 transition-all">סגור</button>
            </div>
          </div>
        </div>
      )}

      {error && <div className="mx-1 px-4 py-4 bg-red-50 text-red-600 rounded-[1.5rem] text-[12px] font-bold text-center">{error}</div>}

      <div className="relative">
        <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-4 px-1">מוצרים בטוחים שסרקת</h3>
        {safeHistory.length === 0 ? (
          <div className="bg-white border border-black/5 rounded-[2.5rem] p-12 text-center space-y-4 mx-1 premium-shadow">
            <p className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">אין עדיין מוצרים בטוחים</p>
            <button onClick={onNavigate} className="bg-dark text-white px-8 py-4 rounded-2xl font-black text-[10px] uppercase">סרוק עכשיו</button>
          </div>
        ) : (
          <div className="flex overflow-x-auto gap-4 px-1 pb-8 hide-scrollbar snap-x">
            {safeHistory.map((item) => (
              <div key={item.id} className="flex-shrink-0 w-44 snap-center">
                <div className="bg-warriorGreen rounded-[2.5rem] p-5 h-64 flex flex-col justify-between shadow-xl relative overflow-hidden">
                  <div className="absolute top-4 left-4 w-7 h-7 bg-white/30 rounded-full flex items-center justify-center backdrop-blur-md">
                     <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>
                  </div>
                  <div className="flex-1 flex items-center justify-center py-4">
                    <div className="w-20 h-20 bg-white/20 rounded-full blur-xl absolute" />
                    <span className="text-6xl drop-shadow-lg">🍎</span>
                  </div>
                  <div className="text-white space-y-1">
                    <h4 className="font-black text-sm uppercase truncate">{item.productName}</h4>
                    <p className="text-[9px] font-bold text-white/60 uppercase">בטוח לשימוש</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="px-1">
        <div className="bg-dark p-8 rounded-[2.5rem] text-white relative overflow-hidden premium-shadow">
          <h3 className="text-2xl font-black uppercase tracking-tighter mb-1">Safety Monitor</h3>
          <p className="text-[10px] text-warriorGreen font-black tracking-widest uppercase mb-6 opacity-80">בדיקה אוטומטית פעילה</p>
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 bg-warriorGreen rounded-2xl flex items-center justify-center text-dark font-black text-2xl shadow-lg shadow-warriorGreen/20">{activeCount}</div>
            <p className="text-xs font-bold leading-snug flex-1">מערכת ה-AI עוקבת אחר {activeCount} רגישויות שהגדרת בפרופילים שלך.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Profile, Group } from '../types';

interface Props {
  profiles: Profile[];
  groups: Group[];
  onAddProfile: (name: string, allergies: string[], groupId?: string) => void;
  onEditProfile: (id: string, name: string, allergies: string[], groupId?: string) => void;
  onToggleProfile: (id: string) => void;
  onDeleteProfile: (id: string) => void;
  onAddGroup: (name: string) => void;
  onEditGroup: (id: string, name: string) => void;
  onToggleGroup: (id: string) => void;
  onDeleteGroup: (id: string) => void;
}

const COMMON_ALLERGENS = ["חלב", "ביצים", "בוטנים", "אגוזים", "סויה", "חיטה", "גלוטן", "שומשום", "דגים", "פירות ים", "חרדל", "סלרי"];

const ProfileManager: React.FC<Props> = ({ 
  profiles, groups, onAddProfile, onEditProfile, onToggleProfile, onDeleteProfile, 
  onAddGroup, onEditGroup, onToggleGroup, onDeleteGroup 
}) => {
  const [showAddProfile, setShowAddProfile] = useState(false);
  const [showAddGroup, setShowAddGroup] = useState(false);
  const [editingProfile, setEditingProfile] = useState<Profile | null>(null);
  const [editingGroup, setEditingGroup] = useState<Group | null>(null);

  const [formData, setFormData] = useState({ name: '', allergies: [] as string[], groupId: '' });
  const [groupFormData, setGroupFormData] = useState({ name: '' });
  const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

  const handleToggleAllergy = (allergy: string) => {
    setFormData(prev => ({
      ...prev,
      allergies: prev.allergies.includes(allergy) ? prev.allergies.filter(a => a !== allergy) : [...prev.allergies, allergy]
    }));
  };

  const startEditProfile = (p: Profile) => {
    setEditingProfile(p);
    setFormData({ name: p.name, allergies: p.allergies, groupId: p.groupId || '' });
    setShowAddProfile(true);
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.name && formData.allergies.length > 0) {
      if (editingProfile) {
        onEditProfile(editingProfile.id, formData.name, formData.allergies, formData.groupId || undefined);
      } else {
        onAddProfile(formData.name, formData.allergies, formData.groupId || undefined);
      }
      resetProfileForm();
    }
  };

  const resetProfileForm = () => {
    setShowAddProfile(false);
    setEditingProfile(null);
    setFormData({ name: '', allergies: [], groupId: '' });
  };

  const handleGroupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (groupFormData.name) {
      if (editingGroup) {
        onEditGroup(editingGroup.id, groupFormData.name);
      } else {
        onAddGroup(groupFormData.name);
      }
      setShowAddGroup(false);
      setEditingGroup(null);
      setGroupFormData({ name: '' });
    }
  };

  const startEditGroup = (g: Group) => {
    setEditingGroup(g);
    setGroupFormData({ name: g.name });
    setShowAddGroup(true);
  };

  const renderProfileCard = (profile: Profile) => {
    const group = groups.find(g => g.id === profile.groupId);
    const isGroupDisabled = group && !group.enabled;
    const effectiveEnabled = profile.enabled && !isGroupDisabled;

    return (
      <div key={profile.id} className={`bg-white p-5 rounded-[2rem] border island-shadow transition-all relative ${effectiveEnabled ? 'border-black/5' : 'opacity-40 grayscale'}`}>
        <div className="flex justify-between items-start">
          <div className="flex gap-2">
            <button onClick={() => onDeleteProfile(profile.id)} className="text-gray-200 hover:text-red-500 transition-colors p-1"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
            <button onClick={() => startEditProfile(profile)} className="text-gray-200 hover:text-blue-500 transition-colors p-1"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
          </div>

          <div className="flex-1 flex flex-col items-end">
            <div className="flex items-center gap-3 mb-1">
              <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${profile.enabled ? 'bg-warriorGreen text-white' : 'bg-gray-100 text-gray-400'}`}>{profile.enabled ? 'ON' : 'OFF'}</button>
              <h4 className="font-black text-dark text-lg uppercase tracking-tight">{profile.name}</h4>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black text-lg ${effectiveEnabled ? 'bg-dark text-warriorGreen' : 'bg-gray-100 text-gray-300'}`}>{profile.name[0].toUpperCase()}</div>
            </div>
            <div className="flex flex-wrap gap-1.5 justify-end mt-2">
              {profile.allergies.map(a => (<span key={a} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${effectiveEnabled ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-300'}`}>{a}</span>))}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-10 py-6 animate-in slide-in-from-right duration-500 pb-10">
      <div className="px-1">
        <h2 className="text-3xl font-black text-dark tracking-tighter uppercase leading-[0.85] mb-2">Warrior<br/><span className="text-warriorGreen">Profiles</span></h2>
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-widest">ניהול יחידות וקבוצות</p>
      </div>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">קבוצות</h3>
          <button onClick={() => { setEditingGroup(null); setGroupFormData({ name: '' }); setShowAddGroup(true); }} className="w-8 h-8 bg-dark text-white rounded-full flex items-center justify-center"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg></button>
        </div>

        {showAddGroup && (
          <form onSubmit={handleGroupSubmit} className="bg-white p-6 rounded-[2rem] border island-shadow space-y-4 animate-in zoom-in">
            <input autoFocus className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" placeholder="שם הקבוצה" value={groupFormData.name} onChange={e => setGroupFormData({ name: e.target.value })} />
            <div className="flex gap-2">
              <button type="submit" className="flex-1 bg-dark text-white py-3 rounded-xl text-xs font-black uppercase">{editingGroup ? 'עדכן' : 'שמור'}</button>
              <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-3 text-gray-400 text-xs font-bold uppercase">ביטול</button>
            </div>
          </form>
        )}

        {groups.map(group => {
          const isCollapsed = collapsedGroups.has(group.id);
          const nestedProfiles = profiles.filter(p => p.groupId === group.id);
          return (
            <div key={group.id} className="space-y-3">
              <div className="bg-white p-4 rounded-2xl border border-black/5 flex items-center justify-between island-shadow cursor-pointer" onClick={() => setCollapsedGroups(prev => { const n = new Set(prev); n.has(group.id) ? n.delete(group.id) : n.add(group.id); return n; })}>
                <div className="flex items-center gap-2" onClick={e => e.stopPropagation()}>
                  <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-200 hover:text-red-500"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  <button onClick={() => startEditGroup(group)} className="p-1 text-gray-200 hover:text-blue-500"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                  <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${group.enabled ? 'bg-warriorGreen/10 text-warriorDarkGreen' : 'bg-gray-50 text-gray-400'}`}>{group.enabled ? 'Active' : 'Off'}</button>
                </div>
