                {COMMON_ALLERGENS.map(a => (
                  <label key={a} className={`flex items-center gap-3 p-3 rounded-xl border transition-all cursor-pointer ${formData.allergies.includes(a) ? 'bg-dark border-dark text-warriorGreen' : 'bg-gray-50 border-transparent text-gray-400 font-bold'}`}>
                    <input type="checkbox" className="hidden" checked={formData.allergies.includes(a)} onChange={() => handleToggleAllergy(a)} />
                    <span className="text-xs font-black uppercase">{a}</span>
                  </label>
                ))}
              </div>
            </div>
            <select className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" value={formData.groupId} onChange={e => setFormData({ ...formData, groupId: e.target.value })}>
              <option value="">ללא קבוצה</option>
              {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
            </select>
            <div className="flex gap-2">
              <button type="submit" className="flex-1 bg-warriorGreen text-dark py-4 rounded-xl text-xs font-black uppercase">{editingProfile ? 'עדכן פרופיל' : 'צור פרופיל'}</button>
              <button type="button" onClick={resetProfileForm} className="px-4 py-4 text-gray-400 text-xs font-bold uppercase">Cancel</button>
            </div>
          </form>
        )}

        {profiles.filter(p => !p.groupId).map(renderProfileCard)}
      </section>
    </div>
  );
};

export default ProfileManager;

import React, { useState, useEffect } from 'react';
import { User, Profile, Group, HistoryItem } from './types';
import { db } from './services/db';
import Login from './components/Login';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import ProfileManager from './components/ProfileManager';
import Scanner from './components/Scanner';
import History from './components/History';
import Account from './components/Account';
import Navigation from './components/Navigation';

type View = 'onboarding' | 'dashboard' | 'profiles' | 'scan' | 'history' | 'account';

export default function App() {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<View>('dashboard');
  const [profiles, setProfiles] = useState<Profile[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  useEffect(() => {
    const savedEmail = localStorage.getItem('current_warrior_email');
    if (savedEmail) {
      const userData = db.getUserData(savedEmail);
      setUser({ email: savedEmail, onboardingComplete: userData.profiles.length > 0 });
      setProfiles(userData.profiles);
      setGroups(userData.groups);
      setHistory(userData.history);
      if (userData.profiles.length === 0) setView('onboarding');
    }
  }, []);

  useEffect(() => {
    if (user) {
      db.saveUserData(user.email, { profiles, groups, history });
    }
  }, [user, profiles, groups, history]);

  const handleLogin = (email: string) => {
    const userData = db.getUserData(email);
    const hasProfiles = userData.profiles.length > 0;
    setUser({ email, onboardingComplete: hasProfiles });
    setProfiles(userData.profiles);
    setGroups(userData.groups);
    setHistory(userData.history);
    localStorage.setItem('current_warrior_email', email);
    setView(hasProfiles ? 'dashboard' : 'onboarding');
  };

  const completeOnboarding = (name: string, allergies: string[]) => {
    const newProfile: Profile = { id: crypto.randomUUID(), name, allergies, enabled: true };
    setProfiles([newProfile]);
    setUser(prev => prev ? { ...prev, onboardingComplete: true } : null);
    setView('dashboard');
  };

  const addProfile = (name: string, allergies: string[], groupId?: string) => {
    setProfiles(prev => [...prev, { id: crypto.randomUUID(), name, allergies, enabled: true, groupId }]);
  };

  const editProfile = (id: string, name: string, allergies: string[], groupId?: string) => {
    setProfiles(prev => prev.map(p => p.id === id ? { ...p, name, allergies, groupId } : p));
  };

  const editGroup = (id: string, name: string) => {
    setGroups(prev => prev.map(g => g.id === id ? { ...g, name } : g));
  };

  const handleLogout = () => {
    setUser(null);
    setProfiles([]);
    setGroups([]);
    setHistory([]);
    localStorage.removeItem('current_warrior_email');
  };

  const activeAllergens = Array.from(new Set(
    profiles
      .filter(p => {
        if (!p.enabled) return false;
        if (p.groupId) {
          const group = groups.find(g => g.id === p.groupId);
          return group?.enabled ?? true;
        }
        return true;
      })
      .flatMap(p => p.allergies)
  ));

  if (!user) return <Login onLogin={handleLogin} />;
  if (view === 'onboarding') return <Onboarding onComplete={completeOnboarding} />;

  return (
    <div className="min-h-screen bg-appBg pb-24 relative max-w-md mx-auto flex flex-col shadow-2xl overflow-x-hidden" dir="rtl">
      <div className="fixed top-4 left-0 right-0 z-50 px-4 max-w-md mx-auto pointer-events-none">
        <div className="bg-white island-shadow border border-black/5 rounded-full py-2 px-4 flex items-center justify-between pointer-events-auto">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-warriorGreen rounded-full flex items-center justify-center font-black text-white text-[10px]">W</div>
            <span className="text-xs font-black text-dark uppercase tracking-tighter">Allergy Warrior</span>
          </div>
          <div className="flex items-center gap-3">
            <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border text-[10px] font-bold ${activeAllergens.length > 0 ? 'bg-warriorGreen/10 border-warriorGreen/20 text-warriorDarkGreen' : 'bg-gray-100'}`}>
              <div className={`w-1.5 h-1.5 rounded-full ${activeAllergens.length > 0 ? 'bg-warriorGreen animate-pulse' : 'bg-gray-400'}`} />
              <span>אלרגיות: {activeAllergens.length}</span>
            </div>
            <div className="w-8 h-8 bg-gray-50 border border-black/5 rounded-full flex items-center justify-center text-[10px] font-bold text-dark">{user.email[0].toUpperCase()}</div>
          </div>
        </div>
      </div>

      <main className="flex-1 mt-16 px-4 py-4 overflow-y-auto">
        {view === 'dashboard' && <Dashboard history={history} onNavigate={() => setView('scan')} activeAllergens={activeAllergens} onScanComplete={(i) => setHistory(p => [{ ...i, id: crypto.randomUUID(), timestamp: Date.now() }, ...p])} />}
        {view === 'profiles' && <ProfileManager profiles={profiles} groups={groups} onAddProfile={addProfile} onEditProfile={editProfile} onToggleProfile={(id) => setProfiles(p => p.map(x => x.id === id ? { ...x, enabled: !x.enabled } : x))} onDeleteProfile={(id) => setProfiles(p => p.filter(x => x.id !== id))} onAddGroup={(name) => setGroups(p => [...p, { id: crypto.randomUUID(), name, enabled: true }])} onEditGroup={editGroup} onToggleGroup={(id) => setGroups(p => p.map(x => x.id === id ? { ...x, enabled: !x.enabled } : x))} onDeleteGroup={(id) => { setGroups(p => p.filter(x => x.id !== id)); setProfiles(p => p.map(x => x.groupId === id ? { ...x, groupId: undefined } : x)); }} />}
        {view === 'scan' && <Scanner activeAllergens={activeAllergens} onScanComplete={(i) => setHistory(p => [{ ...i, id: crypto.randomUUID(), timestamp: Date.now() }, ...p])} onClose={() => setView('dashboard')} />}
        {view === 'history' && <History history={history} />}
        {view === 'account' && <Account user={user} onLogout={handleLogout} profilesCount={profiles.length} historyCount={history.length} />}
      </main>

      <Navigation currentView={view} setView={setView} />
    </div>
  );
}

import React, { useState } from 'react';
import { Profile, Group } from '../types';

interface Props {
  profiles: Profile[];
  groups: Group[];
  onAddProfile: (name: string, allergies: string[], groupId?: string) => void;
  onEditProfile: (id: string, name: string, allergies: string[], groupId?: string) => void;
  onToggleProfile: (id: string) => void;
  onDeleteProfile: (id: string) => void;
  onAddGroup: (name: string) => void;
  onEditGroup: (id: string, name: string) => void;
  onToggleGroup: (id: string) => void;
  onDeleteGroup: (id: string) => void;
}

const COMMON_ALLERGENS = ["חלב", "ביצים", "בוטנים", "אגוזים", "סויה", "חיטה", "גלוטן", "שומשום", "דגים", "פירות ים", "חרדל", "סלרי"];

const ProfileManager: React.FC<Props> = ({ 
  profiles, groups, onAddProfile, onEditProfile, onToggleProfile, onDeleteProfile, 
  onAddGroup, onEditGroup, onToggleGroup, onDeleteGroup 
}) => {
  const [showAddProfile, setShowAddProfile] = useState(false);
  const [showAddGroup, setShowAddGroup] = useState(false);
  const [editingProfile, setEditingProfile] = useState<Profile | null>(null);
  const [editingGroup, setEditingGroup] = useState<Group | null>(null);

  const [formData, setFormData] = useState({ name: '', allergies: [] as string[], groupId: '' });
  const [groupFormData, setGroupFormData] = useState({ name: '' });
  const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());

  const handleToggleAllergy = (allergy: string) => {
    setFormData(prev => ({
      ...prev,
      allergies: prev.allergies.includes(allergy) ? prev.allergies.filter(a => a !== allergy) : [...prev.allergies, allergy]
    }));
  };

  const startEditProfile = (p: Profile) => {
    setEditingProfile(p);
    setFormData({ name: p.name, allergies: p.allergies, groupId: p.groupId || '' });
    setShowAddProfile(true);
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.name && formData.allergies.length > 0) {
      if (editingProfile) {
        onEditProfile(editingProfile.id, formData.name, formData.allergies, formData.groupId || undefined);
      } else {
        onAddProfile(formData.name, formData.allergies, formData.groupId || undefined);
      }
      resetProfileForm();
    }
  };

  const resetProfileForm = () => {
    setShowAddProfile(false);
    setEditingProfile(null);
    setFormData({ name: '', allergies: [], groupId: '' });
  };

  const handleGroupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (groupFormData.name) {
      if (editingGroup) {
        onEditGroup(editingGroup.id, groupFormData.name);
      } else {
        onAddGroup(groupFormData.name);
      }
      setShowAddGroup(false);
      setEditingGroup(null);
      setGroupFormData({ name: '' });
    }
  };

  const startEditGroup = (g: Group) => {
    setEditingGroup(g);
    setGroupFormData({ name: g.name });
    setShowAddGroup(true);
  };

  const renderProfileCard = (profile: Profile) => {
    const group = groups.find(g => g.id === profile.groupId);
    const isGroupDisabled = group && !group.enabled;
    const effectiveEnabled = profile.enabled && !isGroupDisabled;

    return (
      <div key={profile.id} className={`bg-white p-5 rounded-[2rem] border island-shadow transition-all relative ${effectiveEnabled ? 'border-black/5' : 'opacity-40 grayscale'}`}>
        <div className="flex justify-between items-start">
          <div className="flex gap-2">
            <button onClick={() => onDeleteProfile(profile.id)} className="text-gray-200 hover:text-red-500 transition-colors p-1"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
            <button onClick={() => startEditProfile(profile)} className="text-gray-200 hover:text-blue-500 transition-colors p-1"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
          </div>

          <div className="flex-1 flex flex-col items-end">
            <div className="flex items-center gap-3 mb-1">
              <button onClick={() => onToggleProfile(profile.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${profile.enabled ? 'bg-warriorGreen text-white' : 'bg-gray-100 text-gray-400'}`}>{profile.enabled ? 'ON' : 'OFF'}</button>
              <h4 className="font-black text-dark text-lg uppercase tracking-tight">{profile.name}</h4>
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black text-lg ${effectiveEnabled ? 'bg-dark text-warriorGreen' : 'bg-gray-100 text-gray-300'}`}>{profile.name[0].toUpperCase()}</div>
            </div>
            <div className="flex flex-wrap gap-1.5 justify-end mt-2">
              {profile.allergies.map(a => (<span key={a} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${effectiveEnabled ? 'bg-red-500 text-white' : 'bg-gray-100 text-gray-300'}`}>{a}</span>))}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-10 py-6 animate-in slide-in-from-right duration-500 pb-10">
      <div className="px-1">
        <h2 className="text-3xl font-black text-dark tracking-tighter uppercase leading-[0.85] mb-2">Warrior<br/><span className="text-warriorGreen">Profiles</span></h2>
        <p className="text-[10px] font-extrabold text-gray-400 uppercase tracking-widest">ניהול יחידות וקבוצות</p>
      </div>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">קבוצות</h3>
          <button onClick={() => { setEditingGroup(null); setGroupFormData({ name: '' }); setShowAddGroup(true); }} className="w-8 h-8 bg-dark text-white rounded-full flex items-center justify-center"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg></button>
        </div>

        {showAddGroup && (
          <form onSubmit={handleGroupSubmit} className="bg-white p-6 rounded-[2rem] border island-shadow space-y-4 animate-in zoom-in">
            <input autoFocus className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" placeholder="שם הקבוצה" value={groupFormData.name} onChange={e => setGroupFormData({ name: e.target.value })} />
            <div className="flex gap-2">
              <button type="submit" className="flex-1 bg-dark text-white py-3 rounded-xl text-xs font-black uppercase">{editingGroup ? 'עדכן' : 'שמור'}</button>
              <button type="button" onClick={() => setShowAddGroup(false)} className="px-4 py-3 text-gray-400 text-xs font-bold uppercase">ביטול</button>
            </div>
          </form>
        )}

        {groups.map(group => {
          const isCollapsed = collapsedGroups.has(group.id);
          const nestedProfiles = profiles.filter(p => p.groupId === group.id);
          return (
            <div key={group.id} className="space-y-3">
              <div className="bg-white p-4 rounded-2xl border border-black/5 flex items-center justify-between island-shadow cursor-pointer" onClick={() => setCollapsedGroups(prev => { const n = new Set(prev); n.has(group.id) ? n.delete(group.id) : n.add(group.id); return n; })}>
                <div className="flex items-center gap-2" onClick={e => e.stopPropagation()}>
                  <button onClick={() => onDeleteGroup(group.id)} className="p-1 text-gray-200 hover:text-red-500"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                  <button onClick={() => startEditGroup(group)} className="p-1 text-gray-200 hover:text-blue-500"><svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg></button>
                  <button onClick={() => onToggleGroup(group.id)} className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${group.enabled ? 'bg-warriorGreen/10 text-warriorDarkGreen' : 'bg-gray-50 text-gray-400'}`}>{group.enabled ? 'Active' : 'Off'}</button>
                </div>
                <div className="flex items-center gap-3"><span className={`font-black text-sm uppercase ${group.enabled ? 'text-dark' : 'text-gray-300'}`}>{group.name}</span><svg className={`h-4 w-4 text-gray-400 transition-transform ${isCollapsed ? '' : 'rotate-180'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg></div>
              </div>
              {!isCollapsed && nestedProfiles.map(renderProfileCard)}
            </div>
          );
        })}
      </section>

      <section className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-xs font-black text-dark uppercase tracking-widest">פרופילים</h3>
          {/* Fix: Call sequential void functions within a block instead of using logical OR operator */}
          <button onClick={() => { resetProfileForm(); setShowAddProfile(true); }} className="w-8 h-8 bg-warriorGreen text-dark rounded-full flex items-center justify-center"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg></button>
        </div>

        {showAddProfile && (
          <form onSubmit={handleProfileSubmit} className="bg-white p-6 rounded-[2.5rem] border island-shadow space-y-6 animate-in zoom-in">
            <input autoFocus className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" placeholder="שם הפרופיל" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
            <div className="space-y-3">
              <label className="text-[10px] font-black text-gray-400 uppercase">Select Allergies</label>
              <div className="grid grid-cols-2 gap-2 max-h-48 overflow-y-auto pr-2 hide-scrollbar">
                {COMMON_ALLERGENS.map(a => (
                  <label key={a} className={`flex items-center gap-3 p-3 rounded-xl border transition-all cursor-pointer ${formData.allergies.includes(a) ? 'bg-dark border-dark text-warriorGreen' : 'bg-gray-50 border-transparent text-gray-400 font-bold'}`}>
                    <input type="checkbox" className="hidden" checked={formData.allergies.includes(a)} onChange={() => handleToggleAllergy(a)} />
                    <span className="text-xs font-black uppercase">{a}</span>
                  </label>
                ))}
              </div>
            </div>
            <select className="w-full px-5 py-4 rounded-xl bg-gray-50 border border-transparent focus:border-warriorGreen outline-none text-black font-bold text-sm" value={formData.groupId} onChange={e => setFormData({ ...formData, groupId: e.target.value })}>
              <option value="">ללא קבוצה</option>
              {groups.map(g => (<option key={g.id} value={g.id}>{g.name}</option>))}
            </select>
            <div className="flex gap-2">
              <button type="submit" className="flex-1 bg-warriorGreen text-dark py-4 rounded-xl text-xs font-black uppercase">{editingProfile ? 'עדכן פרופיל' : 'צור פרופיל'}</button>
              <button type="button" onClick={resetProfileForm} className="px-4 py-4 text-gray-400 text-xs font-bold uppercase">Cancel</button>
            </div>
          </form>
        )}

        {profiles.filter(p => !p.groupId).map(renderProfileCard)}
      </section>
    </div>
  );
