import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "האם המוצר בטוח לצריכה",
    },
    isEdible: {
      type: Type.BOOLEAN,
      description: "האם מדובר במוצר מזון/אכיל",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "רשימת אלרגנים שנמצאו בעברית",
    },
    summary: {
      type: Type.STRING,
      description: "הסבר קצר ותמציתי בעברית",
    },
  },
  required: ["productName", "isSafe", "isEdible", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  // Use the ultra-fast gemini-3-flash-preview for near-instant results
  const prompt = `
    Analyze this item for these allergens: ${activeAllergens.join(", ")}.

    ${input.text ? `SEARCH: ${input.text}` : "IMAGE: Identify the item."}

    RULES:
    1. If NOT food/drink/consumable, isEdible=false.
    2. If isEdible=false, allergensFound=[], isSafe=false, summary="זה אינו מוצר אכיל, אנא נסה שוב".
    3. If isEdible=true, if ANY match allergens, isSafe=false.
    4. RESPOND IN HEBREW.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0.1, // Slight temperature for better naming consistency
    },
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (e) {
    console.error("Analysis failed", e);
    throw new Error("שגיאה בניתוח הנתונים מהשרת. נסה שוב.");
  }
}

