import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    productName: {
      type: Type.STRING,
      description: "שם המוצר בעברית",
    },
    isSafe: {
      type: Type.BOOLEAN,
      description: "בטוח?",
    },
    isEdible: {
      type: Type.BOOLEAN,
      description: "אכיל?",
    },
    allergensFound: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "אלרגנים שנמצאו",
    },
    summary: {
      type: Type.STRING,
      description: "סיכום קצר מאוד",
    },
  },
  required: ["productName", "isSafe", "isEdible", "allergensFound", "summary"],
};

export async function analyzeProduct(
  input: { text?: string; imageBase64?: string },
  activeAllergens: string[]
): Promise<AnalysisResult> {
  // Ultra-concise prompt for maximum Flash model speed
  const prompt = `
    Analyze for: ${activeAllergens.join(", ")}.
    Item: ${input.text || "See image"}.
    Rules: 1. If non-food, isEdible=false. 2. If match allergens, isSafe=false. 3. Heb ONLY.
    Be ultra-fast and concise.
  `;

  const contents: any[] = [{ text: prompt }];
  if (input.imageBase64) {
    contents.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: input.imageBase64,
      },
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts: contents },
    config: {
      responseMimeType: "application/json",
      responseSchema: ANALYSIS_SCHEMA,
      temperature: 0, // 0 for fastest deterministic response
    },
  });

  try {
    const text = response.text.trim();
    return JSON.parse(text);
  } catch (e) {
    console.error("Analysis failed", e);
    throw new Error("ניתוח מהיר נכשל. נסה שוב.");
  }
}

